import { calculateWeeklyCosts, calculateWeeklyRevenue, calculateStudioNetWorth, generateCashflowForecast } from '@/engine/systems/finance';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Area, XAxis, YAxis, Tooltip, ResponsiveContainer, ComposedChart, Line } from 'recharts';
import { YearInReviewChart } from '@/components/finance/YearInReviewChart';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Sheet, SheetContent, SheetDescription, SheetHeader, SheetTitle, SheetTrigger } from '@/components/ui/sheet';
import { Button } from '@/components/ui/button';
import { History, LayoutDashboard, ReceiptText, TrendingUp, Package, Coins } from 'lucide-react';
import { MarketRatesWidget } from '@/components/finance/MarketRatesWidget';
import { SummaryCards } from '@/components/finance/SummaryCards';
import { ActiveProjectCosts } from '@/components/finance/ActiveProjectCosts';
import { EconomicAnalytics } from '@/components/finance/EconomicAnalytics';
import { ProjectROIAnalytics } from '@/components/finance/ProjectROIAnalytics';
import { RecoupmentTracker } from '@/components/finance/RecoupmentTracker';
import { PiracyImpactMonitor } from '@/components/finance/PiracyImpactMonitor';
import { PassiveIncomePanel } from '@/components/finance/PassiveIncomePanel';
import { useMemo } from 'react';
import { useGameStore } from '@/store/gameStore';
import { useShallow } from 'zustand/react/shallow';
import { formatMoney } from '@/engine/utils';
import { selectProjects } from '@/store/selectors';
import { useFinanceHistory } from '@/hooks/useFinanceHistory';
import { FinancialSnapshot } from '@/engine/types/state.types';

const EMPTY_HISTORY: FinancialSnapshot[] = [];
const EMPTY_PROJECTS: import('@/engine/types').Project[] = [];

export const FinancePanel = () => {
  // Use atomic selectors to prevent unnecessary re-renders when unrelated gameState parts change
  const cash = useGameStore(s => s.gameState?.finance?.cash ?? 0);
  const prestige = useGameStore(s => s.gameState?.studio?.prestige ?? 75);
  const snapshots = useGameStore(useShallow(s => s.snapshots || []));

  // Use useShallow for arrays/objects extracted from state
  // ⚡ Bolt: Removed inline array allocation using Object.values() to prevent unnecessary re-renders
  const projectsMemo = useGameStore(useShallow(s => s.gameState ? selectProjects(s.gameState) : EMPTY_PROJECTS));

  // Data Shedding: Use TanStack Query for historical data
  const financeHistory = useFinanceHistory() ?? EMPTY_HISTORY;

  // Need entire gameState for complex calculations like Net Worth and Forecasts
  // ⚡ The Framerate Fanatic: Moved complex calculations inside the Zustand selector with useShallow to prevent React from re-rendering unless the final computed numbers actually change.
  const { weeklyCosts, netDelta, studioNetWorth, forecast } = useGameStore(useShallow(s => {
    const state = s.gameState;
    if (!state) return { weeklyCosts: 0, netDelta: 0, studioNetWorth: 0, forecast: [] };
    const costs = calculateWeeklyCosts(state);
    const rev = calculateWeeklyRevenue(state);
    return {
      weeklyCosts: costs,
      netDelta: rev - costs,
      studioNetWorth: calculateStudioNetWorth(state),
      forecast: generateCashflowForecast(state, 12)
    };
  }));

  const activeProjects = useMemo(() =>
    projectsMemo.filter(p => p.state === 'development' || p.state === 'production'),
    [projectsMemo]
  );

  const releasedProjects = useMemo(() => 
    projectsMemo.filter(p => p.state === 'released' || p.state === 'post_release' || p.state === 'archived').sort((a,b) => (b.revenue || 0) - (a.revenue || 0)),
    [projectsMemo]
  );

  const recoupmentData = useMemo(() => releasedProjects.map(p => {
    const revenue = p.revenue || 0;
    const budget = p.budget || 1;
    const recouped = Math.min(100, Math.round((revenue / budget) * 100));
    return {
      projectId: p.id,
      projectTitle: p.title,
      format: (p.format === 'film' ? 'film' : p.format === 'tv' ? 'tv' : 'streaming') as 'film' | 'tv' | 'streaming',
      budget,
      revenue,
      recouped,
      status: revenue >= budget * 2 ? 'profitable' as const : revenue >= budget ? 'recouped' as const : revenue >= budget * 0.7 ? 'in_progress' as const : 'at_risk' as const,
      profitMargin: budget > 0 ? Math.round(((revenue - budget) / budget) * 100) : 0,
    };
  }), [releasedProjects]);

  const piracyData = useMemo(() => releasedProjects.slice(0, 5).map(p => ({
    projectId: p.id,
    projectTitle: p.title,
    format: (p.format === 'film' ? 'film' : 'tv') as 'film' | 'tv',
    totalDownloads: 0,
    estimatedRevenueLoss: 0,
    byRegion: [],
    daysSinceRelease: 0,
  })), [releasedProjects]);

  const passiveStreams = useMemo(() => releasedProjects.slice(0, 5).map(p => ({
    type: 'library' as const,
    source: p.title,
    weeklyRevenue: Math.round((p.revenue || 0) * 0.005),
    totalToDate: Math.round((p.revenue || 0) * 0.05),
    growth: 2,
    trend: 'stable' as const,
  })), [releasedProjects]);

  const passiveTotalWeekly = useMemo(() => passiveStreams.reduce((s, p) => s + p.weeklyRevenue, 0), [passiveStreams]);
  const passiveTotalYTD = useMemo(() => passiveStreams.reduce((s, p) => s + p.totalToDate, 0), [passiveStreams]);

  const latestFinanceSnapshot = useMemo(() =>
    financeHistory.length > 0 ? financeHistory[financeHistory.length - 1] : null,
    [financeHistory]
  );

  const chartData = useMemo(() => {
    if (!financeHistory || financeHistory.length === 0) return [];

    // Convert snapshots to chart format
    const history = financeHistory.map((h: FinancialSnapshot) => ({
      week: h.week,
      isForecast: false,
      histCash: h.cash,
      histRevenue: h.revenue.theatrical + h.revenue.streaming + h.revenue.merch + h.revenue.passive,
      histCosts: h.expenses.production + h.expenses.marketing + h.expenses.burn + h.expenses.interest + h.expenses.royalties,
      ...h.revenue,
      ...h.expenses
    }));

    const projected = forecast.map(f => ({
      week: f.week,
      isForecast: true,
      projCash: f.projected,
      projRevenue: 0,
      projCosts: 0
    }));

    if (history.length > 0 && projected.length > 0) {
      const last = history[history.length - 1];
      projected.unshift({
        ...last,
        projCash: last.histCash,
        projRevenue: last.histRevenue,
        projCosts: last.histCosts,
        isForecast: true,
      } as unknown as typeof projected[0]);
    }

    return [...history, ...projected];
  }, [financeHistory, forecast]);

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500 pb-12">
      <div className="flex items-center justify-between border-b border-border/40 pb-4 bg-gradient-to-r from-background to-transparent">
        <h2 className="text-3xl font-display font-black tracking-tight bg-clip-text text-transparent bg-gradient-to-r from-foreground to-foreground/70 drop-shadow-sm">
          Financials & Forecasts
        </h2>

        <Sheet>
          <SheetTrigger asChild>
            <Button 
              variant="outline" 
              size="sm" 
              tooltip="Access comprehensive historical financial records and audit logs"
              className="font-display font-black uppercase tracking-widest text-[10px] gap-2 hover:bg-primary/10 hover:text-primary transition-all"
            >
              <ReceiptText className="w-3 h-3" />
              View Full Ledger
            </Button>
          </SheetTrigger>
          <SheetContent className="w-[400px] sm:w-[540px] border-l border-border/40 bg-background/95 backdrop-blur-xl">
            <SheetHeader className="border-b border-border/20 pb-6">
              <SheetTitle className="font-display text-2xl font-black uppercase tracking-tight flex items-center gap-2">
                <Coins className="w-6 h-6 text-primary" />
                Studio Ledger
              </SheetTitle>
              <SheetDescription className="text-xs font-medium tracking-wide">
                Historical record of yearly performance and financial benchmarks.
              </SheetDescription>
            </SheetHeader>
            <div className="mt-8 space-y-4 overflow-y-auto max-h-[calc(100vh-180px)] pr-2 custom-scrollbar">
              {snapshots.slice().reverse().map((s, i) => (
                <Card key={i} className="border-border/40 bg-card/40 backdrop-blur-md shadow-sm group hover:border-primary/30 transition-all duration-300">
                  <CardContent className="p-5">
                    <div className="flex justify-between items-start mb-4">
                      <div className="space-y-1">
                        <p className="text-[10px] text-muted-foreground uppercase font-black tracking-widest">Fiscal Year</p>
                        <p className="text-2xl font-display font-black text-foreground">{s.year}</p>
                      </div>
                      <Badge variant="outline" className="text-[9px] font-black tracking-widest uppercase bg-primary/5 text-primary border-primary/20">
                        Snapshot Taken
                      </Badge>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div className="bg-background/40 p-3 rounded-lg border border-border/20">
                        <p className="text-[9px] text-muted-foreground uppercase font-black tracking-widest mb-1 flex items-center gap-1">
                          <TrendingUp className="w-2 h-2" /> Total Funds
                        </p>
                        <p className="text-sm font-bold font-mono text-success">{formatMoney(s.funds)}</p>
                      </div>
                      <div className="bg-background/40 p-3 rounded-lg border border-border/20">
                        <p className="text-[9px] text-muted-foreground uppercase font-black tracking-widest mb-1 flex items-center gap-1">
                          <Package className="w-2 h-2" /> Projects
                        </p>
                        <p className="text-sm font-bold font-mono">{s.completedProjects} Completed</p>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              ))}
              {(snapshots.length === 0) && (
                <div className="text-center py-12 opacity-50 px-8">
                   <History className="w-12 h-12 mx-auto mb-4 text-muted-foreground/30" />
                   <p className="text-sm font-bold uppercase tracking-widest mb-2">No Records Yet</p>
                   <p className="text-[10px] font-medium leading-relaxed">The ledger is updated automatically at the end of every fiscal year (Week 52).</p>
                </div>
              )}
            </div>
          </SheetContent>
        </Sheet>
      </div>

      <Tabs defaultValue="current" className="space-y-6">
        <TabsList className="bg-muted/30 backdrop-blur-md border border-border/40 p-1">
          <TabsTrigger value="current" className="gap-2 font-display font-black uppercase tracking-widest text-[10px] data-[state=active]:bg-primary data-[state=active]:text-primary-foreground transition-all px-6">
            <LayoutDashboard className="w-3 h-3" />
            Current Operations
          </TabsTrigger>
          <TabsTrigger value="history" className="gap-2 font-display font-black uppercase tracking-widest text-[10px] data-[state=active]:bg-primary data-[state=active]:text-primary-foreground transition-all px-6">
            <History className="w-3 h-3" />
            Historical Trends
          </TabsTrigger>
        </TabsList>

        <TabsContent value="current" className="space-y-6 m-0 outline-none">

      {/* Summary Cards */}
      <SummaryCards metrics={[
        { label: 'Available Cash', value: formatMoney(cash), color: cash < 0 ? 'text-destructive drop-shadow-[0_0_8px_rgba(239,68,68,0.4)]' : 'text-primary drop-shadow-[0_0_8px_rgba(234,179,8,0.4)]', bg: 'from-card/80 to-card/40', tooltip: 'Total liquid capital available for studio operations and project funding.' },
        { label: 'Total Net Worth', value: formatMoney(studioNetWorth), color: 'text-foreground', bg: 'from-card/80 to-card/40', tooltip: 'Estimated total value of all studio assets, including cash, IP, and talent contracts.' },
        { label: 'Projected Net Delta', value: `${netDelta >= 0 ? '+' : ''}${formatMoney(netDelta)}/wk`, color: netDelta >= 0 ? 'text-success drop-shadow-[0_0_8px_rgba(34,197,94,0.4)]' : 'text-destructive drop-shadow-[0_0_8px_rgba(239,68,68,0.4)]', bg: netDelta >= 0 ? 'from-success/5 to-transparent' : 'from-destructive/5 to-transparent', tooltip: 'Estimated weekly profit or loss based on current revenue streams and production burn.' },
        { label: '12-Wk Forecast Cash', value: formatMoney(forecast.length > 0 ? forecast[forecast.length - 1].projected : 0), color: 'text-purple-400 drop-shadow-[0_0_8px_rgba(192,132,252,0.4)]', bg: 'from-purple-500/5 to-transparent', tooltip: 'Projected cash position in 12 weeks based on current trajectory and known milestones.' },
      ]} />

      <div className="grid grid-cols-3 gap-6 h-[400px]">
        {/* Cash Flow Chart */}
        <div className="col-span-2 flex flex-col h-full">
          <div className="mb-6">
            <MarketRatesWidget />
          </div>

          <Card className="border-border/40 bg-card/60 bg-gradient-to-br from-card/80 to-transparent backdrop-blur-md shadow-sm hover:shadow-[0_8px_30px_rgb(0,0,0,0.12)] transition-all duration-300 flex-1 flex flex-col">
            <CardHeader className="pb-4 border-b border-border/30 bg-background/40 backdrop-blur-sm shrink-0 flex flex-row items-center justify-between">
              <CardTitle className="text-xs font-display font-black uppercase tracking-widest text-foreground/80 drop-shadow-sm">
                Cashflow & Forecast
              </CardTitle>
              <div className="flex items-center gap-3 text-[10px] font-bold tracking-widest uppercase">
                 <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-success"></div> Revenue</div>
                 <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-destructive"></div> Costs</div>
                 <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-primary"></div> Cash History</div>
                 <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-purple-500"></div> Forecast</div>
              </div>
            </CardHeader>
            <CardContent className="pt-6 flex-1 min-h-0">
              <ResponsiveContainer width="100%" height="100%">
                <ComposedChart data={chartData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                  <defs>
                     <linearGradient id="revGrad" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="hsl(142, 71%, 45%)" stopOpacity={0.3} />
                      <stop offset="95%" stopColor="hsl(142, 71%, 45%)" stopOpacity={0} />
                    </linearGradient>
                    <linearGradient id="costGrad" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="hsl(0, 84%, 60%)" stopOpacity={0.3} />
                      <stop offset="95%" stopColor="hsl(0, 84%, 60%)" stopOpacity={0} />
                    </linearGradient>
                  </defs>
                  <XAxis dataKey="week" stroke="hsl(215, 20%, 35%)" fontSize={11} tickLine={false} axisLine={false} tickFormatter={v => `W${v}`} />
                  <YAxis stroke="hsl(215, 20%, 35%)" fontSize={11} tickFormatter={v => formatMoney(v)} tickLine={false} axisLine={false} />
                  <Tooltip
                    contentStyle={{ background: 'rgba(15, 23, 42, 0.8)', border: '1px solid rgba(51, 65, 85, 0.6)', borderRadius: '8px', fontSize: '12px', backdropFilter: 'blur(12px)', boxShadow: '0 4px 20px rgba(0,0,0,0.4)' }}
                    itemStyle={{ fontWeight: 600 }}
                    formatter={(value: number, name: string) => [formatMoney(value), name.replace('hist', '').replace('proj', 'Pred ')]}
                    labelFormatter={l => `Week ${l}`}
                  />

                  {/* Historical Stack */}
                  <Area type="monotone" dataKey="histRevenue" stackId="1" stroke="hsl(142, 71%, 45%)" fill="url(#revGrad)" />
                  <Area type="monotone" dataKey="histCosts" stackId="2" stroke="hsl(0, 84%, 60%)" fill="url(#costGrad)" />

                  {/* Historical Cash Line */}
                  <Line type="monotone" dataKey="histCash" stroke="hsl(48, 96%, 53%)" strokeWidth={3} dot={false} style={{ filter: 'drop-shadow(0 0 4px rgba(234,179,8,0.4))' }} />

                  {/* Forecast Cash Line */}
                  <Line type="monotone" dataKey="projCash" stroke="#a855f7" strokeWidth={3} strokeDasharray="5 5" dot={false} style={{ filter: 'drop-shadow(0 0 4px rgba(168,85,247,0.4))' }} />
                </ComposedChart>
              </ResponsiveContainer>
            </CardContent>
          </Card>
        </div>

        {/* Active Project Costs */}
        <div className="col-span-1 flex flex-col h-full">
          <ActiveProjectCosts activeProjects={activeProjects} weeklyCosts={weeklyCosts} />
        </div>
      </div>

      {/* Deep Economic Analytics */}
      <EconomicAnalytics 
        financeHistory={financeHistory} 
        latestFinanceSnapshot={latestFinanceSnapshot} 
        prestige={prestige} 
      />

      {/* Project ROI Analytics */}
      <ProjectROIAnalytics releasedProjects={releasedProjects} />

      {/* Recoupment Tracker */}
      {recoupmentData.length > 0 && (
        <RecoupmentTracker projects={recoupmentData} />
      )}

      {/* Passive Income Streams */}
      {passiveStreams.length > 0 && (
        <PassiveIncomePanel
          streams={passiveStreams}
          totalWeekly={passiveTotalWeekly}
          totalYTD={passiveTotalYTD}
          topPerformingSource={passiveStreams[0]?.source ?? ''}
        />
      )}

      {/* Piracy Impact Monitor */}
      {piracyData.length > 0 && (
        <PiracyImpactMonitor
          projects={piracyData}
          totalLoss={0}
          studioRiskLevel="low"
          activeProtections={['DRM', 'Watermarking']}
        />
      )}

        </TabsContent>

        <TabsContent value="history" className="m-0 outline-none">
          <YearInReviewChart />
        </TabsContent>
      </Tabs>
    </div>
  );
};

import React from 'react';
import { TimeSeriesChart } from '@/components/charts/TimeSeriesChart';
import { Card } from '@/components/ui/card';
import { tokens } from '@/lib/tokens';
import { cn } from '@/lib/utils';
import { AlertTriangle } from 'lucide-react';
import { Badge } from '@/components/ui/badge';
import { useGameStore } from '@/store/gameStore';
import { selectBudgetBurnData } from '@/store/selectors';

interface BurnRateData {
  week: number;
  planned: number;
  actual: number;
  remaining: number;
}

interface BudgetBurnRateProps {
  data?: BurnRateData[];
  totalBudget?: number;
  projectId?: string;
  className?: string;
}

export const BudgetBurnRate: React.FC<BudgetBurnRateProps> = ({
  data: externalData,
  totalBudget: externalBudget,
  projectId,
  className,
}) => {
  const gameState = useGameStore(s => s.gameState);
  const selectorData = projectId ? selectBudgetBurnData(gameState, projectId) : null;
  const data = externalData || selectorData || [];
  const totalBudget = externalBudget || (selectorData && selectorData[0]?.remaining + selectorData.reduce((sum, d) => sum + d.actual, 0)) || 0;
  const currentBurn = data[data.length - 1]?.actual || 0;
  const plannedBurn = data[data.length - 1]?.planned || 0;
  const variance = currentBurn - plannedBurn;
  const isOverBurn = variance > 0;
  const totalSpent = data.reduce((sum, d) => sum + d.actual, 0);
  const remaining = totalBudget - totalSpent;
  const percentUsed = (totalSpent / totalBudget) * 100;

  const formatCurrency = (value: number) => {
    if (Math.abs(value) >= 1000000) return `$${(value / 1000000).toFixed(1)}M`;
    if (Math.abs(value) >= 1000) return `$${(value / 1000).toFixed(0)}K`;
    return `$${value}`;
  };

  const chartData = data.map(d => ({
    date: `W${d.week}`,
    value: d.actual,
    secondaryValue: d.planned,
  }));

  return (
    <Card className={cn('p-4', tokens.border.default, className)}>
      <div className="flex items-center justify-between mb-4">
        <div>
          <h4 className="font-bold text-sm">Budget Burn Rate</h4>
          <p className={cn('text-[10px]', tokens.text.caption)}>
            Actual vs planned spending
          </p>
        </div>
        <div className="flex items-center gap-2">
          {isOverBurn && (
            <Badge className="text-[9px] bg-red-500/20 text-red-500">
              <AlertTriangle className="h-3 w-3 mr-1" />
              Over burn
            </Badge>
          )}
          <div className={cn(
            'text-lg font-bold',
            percentUsed > 90 ? 'text-red-500' :
            percentUsed > 75 ? 'text-amber-500' : 'text-emerald-500'
          )}>
            {percentUsed.toFixed(0)}%
          </div>
        </div>
      </div>

      <div className="grid grid-cols-3 gap-2 mb-4 text-center">
        <div className="p-2 bg-muted/30 rounded">
          <p className="text-xs font-bold">{formatCurrency(totalSpent)}</p>
          <p className={cn('text-[9px]', tokens.text.caption)}>Spent</p>
        </div>
        <div className="p-2 bg-muted/30 rounded">
          <p className={cn(
            'text-xs font-bold',
            isOverBurn ? 'text-red-500' : 'text-emerald-500'
          )}>
            {formatCurrency(currentBurn)}
          </p>
          <p className={cn('text-[9px]', tokens.text.caption)}>This week</p>
        </div>
        <div className="p-2 bg-muted/30 rounded">
          <p className="text-xs font-bold">{formatCurrency(remaining)}</p>
          <p className={cn('text-[9px]', tokens.text.caption)}>Remaining</p>
        </div>
      </div>

      <TimeSeriesChart
        data={chartData}
        height={140}
        lineColor="#ef4444"
        secondaryLineColor="#3b82f6"
        valueFormatter={formatCurrency}
        showGrid={false}
      />

      <div className="flex items-center justify-center gap-4 mt-2 text-[10px]">
        <div className="flex items-center gap-1">
          <div className="w-3 h-1 bg-red-500" />
          <span>Actual</span>
        </div>
        <div className="flex items-center gap-1">
          <div className="w-3 h-1 bg-blue-500" />
          <span>Planned</span>
        </div>
      </div>
    </Card>
  );
};

export default BudgetBurnRate;

import React from 'react';
import { HeatMap } from '@/components/charts/HeatMap';
import { Card } from '@/components/ui/card';
import { tokens } from '@/lib/tokens';
import { cn } from '@/lib/utils';
import { useGameStore } from '@/store/gameStore';
import { selectGenrePerformanceMatrix } from '@/store/selectors';

interface GenrePerformanceData {
  genre: string;
  metric: string;
  value: number; // ROI percentage or performance score
}

interface GenrePerformanceMatrixProps {
  data?: GenrePerformanceData[];
  className?: string;
}

export const GenrePerformanceMatrix: React.FC<GenrePerformanceMatrixProps> = ({
  data: externalData,
  className,
}) => {
  const gameState = useGameStore(s => s.gameState);
  const data = externalData || selectGenrePerformanceMatrix(gameState);

  // Extract unique genres and metrics
  const genres = Array.from(new Set(data.map(d => d.genre)));
  const metrics = Array.from(new Set(data.map(d => d.metric)));

  // Transform data for heatmap
  const heatmapData = data.map(d => ({
    x: d.metric,
    y: d.genre,
    value: d.value,
  }));

  // Color scale: red (negative) to green (positive)
  const colorScale = [
    '#7f1d1d', // Very negative
    '#991b1b',
    '#b91c1c',
    '#dc2626',
    '#ef4444',
    '#f87171',
    '#fca5a5',
    '#fee2e2', // Near zero
    '#dcfce7',
    '#bbf7d0',
    '#86efac',
    '#4ade80',
    '#22c55e',
    '#16a34a',
    '#15803d',
    '#166534', // Very positive
  ];

  const formatPercent = (value: number) => `${value >= 0 ? '+' : ''}${value}%`;

  return (
    <Card className={cn('p-4', tokens.border.default, className)}>
      <div className="mb-4">
        <h4 className="font-bold text-sm">Genre Performance Matrix</h4>
        <p className={cn('text-[10px]', tokens.text.caption)}>
          ROI by genre and metric (green = positive, red = negative)
        </p>
      </div>

      <HeatMap
        data={heatmapData}
        xLabels={metrics}
        yLabels={genres}
        colorScale={colorScale}
        valueFormatter={formatPercent}
      />
    </Card>
  );
};

export default GenrePerformanceMatrix;

import React from 'react';
import { GaugeChart } from '@/components/charts/GaugeChart';
import { Card } from '@/components/ui/card';
import { tokens } from '@/lib/tokens';
import { cn } from '@/lib/utils';
import { Clock, AlertTriangle, CheckCircle2 } from 'lucide-react';
import { Badge } from '@/components/ui/badge';
import { useGameStore } from '@/store/gameStore';
import { selectProductionSlippage } from '@/store/selectors';

interface SlippageData {
  projectName: string;
  originalEndWeek: number;
  currentEndWeek: number;
  weeksSlipped: number;
  reason: string;
}

interface ProductionSlippageIndicatorProps {
  projects?: SlippageData[];
  className?: string;
}

export const ProductionSlippageIndicator: React.FC<ProductionSlippageIndicatorProps> = ({
  projects: externalProjects,
  className,
}) => {
  const gameState = useGameStore(s => s.gameState);
  const projects = externalProjects || selectProductionSlippage(gameState);
  const totalSlipped = projects.length;
  const avgSlippage = totalSlipped > 0 
    ? projects.reduce((sum, p) => sum + p.weeksSlipped, 0) / totalSlipped 
    : 0;

  // Gauge value: 0 = perfect, 100 = disaster (based on avg slippage)
  const gaugeValue = Math.min((avgSlippage / 4) * 100, 100);

  const getStatus = () => {
    if (gaugeValue < 25) return { label: 'On Track', color: '#10b981', icon: CheckCircle2 };
    if (gaugeValue < 50) return { label: 'Minor Delays', color: '#f59e0b', icon: Clock };
    if (gaugeValue < 75) return { label: 'Significant Delays', color: '#ef4444', icon: AlertTriangle };
    return { label: 'Critical', color: '#dc2626', icon: AlertTriangle };
  };

  const status = getStatus();
  const Icon = status.icon;

  return (
    <Card className={cn('p-4', tokens.border.default, className)}>
      <div className="flex items-center justify-between mb-3">
        <div>
          <h4 className="font-bold text-sm">Schedule Performance</h4>
          <p className={cn('text-[10px]', tokens.text.caption)}>
            Production timeline adherence
          </p>
        </div>
        <Badge 
          className="text-[9px]"
          style={{ 
            backgroundColor: `${status.color}20`,
            color: status.color,
            borderColor: status.color 
          }}
          variant="outline"
        >
          <Icon className="h-3 w-3 mr-1" />
          {status.label}
        </Badge>
      </div>

      <div className="flex flex-col items-center">
        <GaugeChart
          value={100 - gaugeValue} // Invert: 100 = perfect, 0 = bad
          size={140}
          strokeWidth={10}
          color={status.color}
          label="On-Time Score"
          valueFormatter={(v) => `${v.toFixed(0)}%`}
        />
      </div>

      <div className="space-y-2 mt-3">
        <div className="flex items-center justify-between text-[10px]">
          <span className={tokens.text.caption}>Projects slipped</span>
          <span className="font-medium">{totalSlipped}</span>
        </div>
        <div className="flex items-center justify-between text-[10px]">
          <span className={tokens.text.caption}>Avg delay</span>
          <span className={cn(
            'font-medium',
            avgSlippage > 2 ? 'text-red-500' : 'text-amber-500'
          )}>
            {avgSlippage.toFixed(1)} weeks
          </span>
        </div>
      </div>

      {/* Top slip reasons */}
      {projects.length > 0 && (
        <div className="mt-3 pt-3 border-t border-border/30">
          <p className={cn('text-[10px] font-medium mb-2', tokens.text.caption)}>
            Recent delays:
          </p>
          {projects.slice(0, 3).map((p, idx) => (
            <div key={idx} className="flex items-center justify-between text-[10px] py-1">
              <span className="truncate max-w-[100px]">{p.projectName}</span>
              <span className="text-red-500">+{p.weeksSlipped}w</span>
            </div>
          ))}
        </div>
      )}
    </Card>
  );
};

export default ProductionSlippageIndicator;

import React from 'react';
import { StackedBarChart } from '@/components/charts/StackedBarChart';
import { Card } from '@/components/ui/card';
import { tokens } from '@/lib/tokens';
import { cn } from '@/lib/utils';
import { Clock } from 'lucide-react';
import { useGameStore } from '@/store/gameStore';
import { selectProjectTimelineData } from '@/store/selectors';

interface TimelineData {
  week: string;
  development: number;
  preProduction: number;
  production: number;
  postProduction: number;
  release: number;
}

interface ProjectTimelineProps {
  data?: TimelineData[];
  className?: string;
  weeks?: number;
}

export const ProjectTimeline: React.FC<ProjectTimelineProps> = ({
  data: externalData,
  className,
  weeks = 12,
}) => {
  const gameState = useGameStore(s => s.gameState);
  const data = externalData || selectProjectTimelineData(gameState, weeks);
  const series = [
    { key: 'development', name: 'Development', color: '#94a3b8' },
    { key: 'preProduction', name: 'Pre-Production', color: '#3b82f6' },
    { key: 'production', name: 'Production', color: '#f59e0b' },
    { key: 'postProduction', name: 'Post-Production', color: '#8b5cf6' },
    { key: 'release', name: 'Release', color: '#10b981' },
  ];

  const totalProjects = data.reduce((sum, d) => 
    sum + d.development + d.preProduction + d.production + d.postProduction + d.release, 0
  );

  // Transform data to include label property
  const chartData = data.map(d => ({
    label: d.week,
    development: d.development,
    preProduction: d.preProduction,
    production: d.production,
    postProduction: d.postProduction,
    release: d.release,
  }));

  return (
    <Card className={cn('p-4', tokens.border.default, className)}>
      <div className="flex items-center justify-between mb-4">
        <div>
          <h4 className="font-bold text-sm">Project Pipeline</h4>
          <p className={cn('text-[10px]', tokens.text.caption)}>
            Projects by production phase
          </p>
        </div>
        <div className="flex items-center gap-1">
          <Clock className="h-4 w-4 text-muted-foreground" />
          <span className="text-sm font-medium">{totalProjects} active</span>
        </div>
      </div>

      <StackedBarChart
        data={chartData}
        series={series}
        height={180}
        showGrid={false}
        showLegend={false}
        valueFormatter={(v) => `${v} proj`}
      />

      {/* Phase legend */}
      <div className="flex flex-wrap gap-2 mt-3">
        {series.map((s) => (
          <div key={s.key} className="flex items-center gap-1 text-[9px]">
            <div 
              className="w-2 h-2 rounded-sm" 
              style={{ backgroundColor: s.color }}
            />
            <span>{s.name}</span>
          </div>
        ))}
      </div>
    </Card>
  );
};

export default ProjectTimeline;

import React from 'react';
import { PieChart } from '@/components/charts/PieChart';
import { Card } from '@/components/ui/card';
import { tokens } from '@/lib/tokens';
import { cn } from '@/lib/utils';
import { useGameStore } from '@/store/gameStore';
import { selectRevenueBreakdown } from '@/store/selectors';

interface RevenueSource {
  name: string;
  value: number;
  color?: string;
}

interface RevenueBreakdownProps {
  sources?: RevenueSource[];
  totalRevenue?: number;
  className?: string;
}

export const RevenueBreakdown: React.FC<RevenueBreakdownProps> = ({
  sources: externalSources,
  totalRevenue: externalTotal,
  className,
}) => {
  const gameState = useGameStore(s => s.gameState);
  const sources = externalSources || selectRevenueBreakdown(gameState);
  const totalRevenue = externalTotal || sources.reduce((sum, s) => sum + s.value, 0);
  const defaultColors = [
    '#3b82f6', // Theatrical
    '#10b981', // Streaming
    '#f59e0b', // TV
    '#8b5cf6', // Merchandise
    '#ec4899', // Licensing
    '#06b6d4', // Syndication
    '#84cc16', // Other
  ];

  const data = sources.map((s, i) => ({
    name: s.name,
    value: s.value,
    color: s.color || defaultColors[i % defaultColors.length],
  }));

  const formatCurrency = (value: number) => {
    if (Math.abs(value) >= 1000000) return `$${(value / 1000000).toFixed(1)}M`;
    if (Math.abs(value) >= 1000) return `$${(value / 1000).toFixed(0)}K`;
    return `$${value}`;
  };

  return (
    <Card className={cn('p-4', tokens.border.default, className)}>
      <div className="flex items-center justify-between mb-2">
        <div>
          <h4 className="font-bold text-sm">Revenue Breakdown</h4>
          <p className={cn('text-[10px]', tokens.text.caption)}>
            By source
          </p>
        </div>
        <div className="text-right">
          <p className="text-xl font-bold text-emerald-500">
            {formatCurrency(totalRevenue)}
          </p>
          <p className={cn('text-[10px]', tokens.text.caption)}>Total</p>
        </div>
      </div>

      <PieChart
        data={data}
        height={200}
        innerRadius={40}
        outerRadius={70}
        showTooltip={true}
        showLegend={false}
        valueFormatter={formatCurrency}
      />

      {/* Custom legend */}
      <div className="grid grid-cols-2 gap-2 mt-2">
        {data.map((item) => {
          const percentage = ((item.value / totalRevenue) * 100).toFixed(1);
          return (
            <div key={item.name} className="flex items-center gap-2 text-[10px]">
              <div 
                className="w-3 h-3 rounded-full flex-shrink-0" 
                style={{ backgroundColor: item.color }}
              />
              <span className="truncate">{item.name}</span>
              <span className="text-muted-foreground ml-auto">{percentage}%</span>
            </div>
          );
        })}
      </div>
    </Card>
  );
};

export default RevenueBreakdown;

import React from 'react';
import { RadarChart } from '@/components/charts/RadarChart';
import { Card } from '@/components/ui/card';
import { tokens } from '@/lib/tokens';
import { cn } from '@/lib/utils';
import { FileText, Star, TrendingUp } from 'lucide-react';
import { useGameStore } from '@/store/gameStore';
import { selectScriptQualityMetrics } from '@/store/selectors';

interface QualityMetric {
  metric: string;
  score: number;
  fullMark: number;
}

interface ScriptData {
  title: string;
  writer: string;
  overallScore: number;
  metrics: QualityMetric[];
  trend: 'improving' | 'stable' | 'declining';
}

interface ScriptQualityMetricsProps {
  script?: ScriptData;
  className?: string;
  projectId?: string;
}

export const ScriptQualityMetrics: React.FC<ScriptQualityMetricsProps> = ({
  script: externalScript,
  className,
  projectId,
}) => {
  const gameState = useGameStore(s => s.gameState);
  const selectorResult = projectId ? selectScriptQualityMetrics(gameState, projectId) : null;

  // Handle both ScriptData format and selector's array format
  const script = externalScript || (selectorResult ? {
    title: 'Script',
    writer: 'Unknown',
    overallScore: selectorResult.reduce((sum, m) => sum + m.value, 0) / selectorResult.length,
    metrics: selectorResult.map(m => ({ metric: m.metric, score: m.value, fullMark: 100 })),
    trend: 'stable' as const
  } : null);

  if (!script) {
    return (
      <Card className={cn('p-4', tokens.border.default, className)}>
        <div className="text-center text-muted-foreground text-sm">
          No script data available
        </div>
      </Card>
    );
  }

  const radarData = script.metrics.map(m => ({
    metric: m.metric,
    value: m.score,
    fullMark: m.fullMark,
  }));

  const getTrendIcon = () => {
    switch (script.trend) {
      case 'improving':
        return <TrendingUp className="h-4 w-4 text-emerald-500" />;
      case 'declining':
        return <TrendingUp className="h-4 w-4 text-red-500 rotate-180" />;
      default:
        return <Star className="h-4 w-4 text-amber-500" />;
    }
  };

  const getScoreColor = (score: number) => {
    if (score >= 80) return '#10b981';
    if (score >= 60) return '#f59e0b';
    return '#ef4444';
  };

  return (
    <Card className={cn('p-4', tokens.border.default, className)}>
      <div className="flex items-center justify-between mb-3">
        <div className="flex items-center gap-2">
          <FileText className="h-5 w-5 text-primary" />
          <div>
            <h4 className="font-bold text-sm truncate max-w-[120px]">{script.title}</h4>
            <p className={cn('text-[10px]', tokens.text.caption)}>
              by {script.writer}
            </p>
          </div>
        </div>
        <div className="flex items-center gap-1">
          <span 
            className="text-xl font-bold"
            style={{ color: getScoreColor(script.overallScore) }}
          >
            {script.overallScore}
          </span>
          <span className="text-[10px] text-muted-foreground">/100</span>
        </div>
      </div>

      <RadarChart
        data={radarData}
        height={180}
        color={getScoreColor(script.overallScore)}
        showTooltip={true}
        valueFormatter={(v) => `${v}`}
      />

      <div className="flex items-center justify-between mt-3 pt-3 border-t border-border/30">
        <div className="flex items-center gap-1 text-[10px]">
          <span className={tokens.text.caption}>Quality trend:</span>
          <span className="capitalize">{script.trend}</span>
        </div>
        {getTrendIcon()}
      </div>
    </Card>
  );
};

export default ScriptQualityMetrics;

import React, { useMemo } from 'react';
import { useGameStore } from '@/store/gameStore';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, Radar, Legend, Cell } from 'recharts';
import { formatMoney } from '@/engine/utils';
import { cn } from '@/lib/utils';
import { Building2, Wallet, Trophy, TrendingUp } from 'lucide-react';

interface CompetitorComparisonProps {
  className?: string;
}

export const CompetitorComparison: React.FC<CompetitorComparisonProps> = ({ className }) => {
  const gameState = useGameStore(s => s.gameState);

  const { studio, rivals } = useMemo(() => {
    if (!gameState) {
      return {
        studio: { name: '', prestige: 0 },
        rivals: [],
      };
    }
    return {
      studio: gameState.studio,
      rivals: Object.values(gameState.entities.rivals),
    };
  }, [gameState]);

  // Prepare bar chart data
  const financialData = useMemo(() => {
    if (!gameState) {
      return [];
    }
    const allStudios = [
      { name: studio.name.slice(0, 10), cash: gameState.finance.cash, prestige: studio.prestige, isPlayer: true },
      ...rivals.map(r => ({
        name: r.name.slice(0, 10),
        cash: r.cash,
        prestige: r.prestige,
        isPlayer: false,
      })),
    ];
    return allStudios.sort((a, b) => b.cash - a.cash);
  }, [studio, rivals, gameState]);

  // Prepare radar chart data for multi-dimensional comparison
  const radarData = useMemo(() => {
    if (!gameState || !gameState.finance) {
      return [];
    }
    const maxCash = Math.max(gameState.finance.cash, ...rivals.map(r => r.cash)) || 1;
    const maxProjects = Math.max(
      Object.keys(gameState.entities.projects).length,
      ...rivals.map(r => r.projectIds?.length || 0)
    ) || 1;

    return [
      {
        metric: 'Cash',
        player: (gameState.finance.cash / maxCash) * 100,
        avgRival: rivals.reduce((sum, r) => sum + r.cash, 0) / (rivals.length || 1) / maxCash * 100,
      },
      {
        metric: 'Prestige',
        player: studio.prestige,
        avgRival: rivals.reduce((sum, r) => sum + r.prestige, 0) / (rivals.length || 1),
      },
      {
        metric: 'Projects',
        player: (Object.keys(gameState.entities.projects).length / maxProjects) * 100,
        avgRival: rivals.reduce((sum, r) => sum + (r.projectIds?.length || 0), 0) / (rivals.length || 1) / maxProjects * 100,
      },
      {
        metric: 'Strength',
        player: rivals.length > 0
          ? 100 - (rivals.reduce((sum, r) => sum + r.strength, 0) / rivals.length)
          : 50,
        avgRival: 50,
      },
    ];
  }, [studio, rivals, gameState]);

  if (!gameState) return null;

  const getRank = (value: number, values: number[], ascending = false) => {
    const sorted = [...values].sort((a, b) => ascending ? a - b : b - a);
    return sorted.indexOf(value) + 1;
  };

  const allCashValues = [gameState.finance.cash, ...rivals.map(r => r.cash)];
  const allPrestigeValues = [studio.prestige, ...rivals.map(r => r.prestige)];

  const cashRank = getRank(gameState.finance.cash, allCashValues);
  const prestigeRank = getRank(studio.prestige, allPrestigeValues);

  return (
    <div className={cn("space-y-4", className)}>
      {/* Rank Summary */}
      <div className="grid grid-cols-2 gap-3">
        <div className="p-3 rounded-lg bg-primary/5 border border-primary/20">
          <div className="flex items-center gap-2 mb-2">
            <Wallet className="w-4 h-4 text-primary" />
            <span className="text-[10px] font-bold uppercase tracking-wider text-muted-foreground">Cash Rank</span>
          </div>
          <div className="flex items-baseline gap-1">
            <span className="text-2xl font-black font-display text-primary">#{cashRank}</span>
            <span className="text-xs text-muted-foreground">of {allCashValues.length}</span>
          </div>
        </div>

        <div className="p-3 rounded-lg bg-secondary/5 border border-secondary/20">
          <div className="flex items-center gap-2 mb-2">
            <Trophy className="w-4 h-4 text-secondary" />
            <span className="text-[10px] font-bold uppercase tracking-wider text-muted-foreground">Prestige Rank</span>
          </div>
          <div className="flex items-baseline gap-1">
            <span className="text-2xl font-black font-display text-secondary">#{prestigeRank}</span>
            <span className="text-xs text-muted-foreground">of {allPrestigeValues.length}</span>
          </div>
        </div>
      </div>

      {/* Financial Comparison Chart */}
      <Card className="border-border/50">
        <CardHeader className="pb-2">
          <CardTitle className="text-xs font-black uppercase tracking-wider flex items-center gap-2">
            <Building2 className="w-4 h-4" />
            Financial Power Comparison
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="h-40">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={financialData} layout="vertical" margin={{ left: 0, right: 20, top: 5, bottom: 5 }}>
                <XAxis type="number" hide />
                <YAxis 
                  dataKey="name" 
                  type="category" 
                  width={80}
                  tick={{ fontSize: 10, fontWeight: 600 }}
                  axisLine={false}
                  tickLine={false}
                />
                <Tooltip
                  content={({ active, payload }) => {
                    if (active && payload && payload.length) {
                      const data = payload[0].payload;
                      return (
                        <div className="bg-card border border-border p-2 rounded-lg shadow-lg">
                          <p className={cn("text-xs font-bold", data.isPlayer ? "text-primary" : "text-foreground")}>
                            {data.name} {data.isPlayer && '(You)'}
                          </p>
                          <p className="text-[10px] text-muted-foreground mt-1">
                            Cash: {formatMoney(data.cash)}
                          </p>
                          <p className="text-[10px] text-muted-foreground">
                            Prestige: {data.prestige}
                          </p>
                        </div>
                      );
                    }
                    return null;
                  }}
                />
                <Bar 
                  dataKey="cash" 
                  radius={[0, 4, 4, 0]} 
                  maxBarSize={20}
                  fill="hsl(var(--primary))"
                >
                  {financialData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.isPlayer ? 'hsl(var(--primary))' : 'hsl(var(--muted))'} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </CardContent>
      </Card>

      {/* Multi-dimensional Radar Chart */}
      <Card className="border-border/50">
        <CardHeader className="pb-2">
          <CardTitle className="text-xs font-black uppercase tracking-wider flex items-center gap-2">
            <TrendingUp className="w-4 h-4" />
            Competitive Position
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="h-48">
            <ResponsiveContainer width="100%" height="100%">
              <RadarChart data={radarData}>
                <PolarGrid stroke="hsl(var(--border))" />
                <PolarAngleAxis 
                  dataKey="metric" 
                  tick={{ fontSize: 9, fontWeight: 600, fill: 'hsl(var(--muted-foreground))' }}
                />
                <PolarRadiusAxis angle={90} domain={[0, 100]} tick={false} axisLine={false} />
                <Radar
                  name="Your Studio"
                  dataKey="player"
                  stroke="hsl(var(--primary))"
                  fill="hsl(var(--primary))"
                  fillOpacity={0.3}
                  strokeWidth={2}
                />
                <Radar
                  name="Avg Rival"
                  dataKey="avgRival"
                  stroke="hsl(var(--muted-foreground))"
                  fill="hsl(var(--muted-foreground))"
                  fillOpacity={0.1}
                  strokeWidth={1}
                  strokeDasharray="4 4"
                />
                <Legend 
                  wrapperStyle={{ fontSize: '10px' }}
                  iconType="circle"
                />
              </RadarChart>
            </ResponsiveContainer>
          </div>
        </CardContent>
      </Card>

      {/* Rival List */}
      <div className="space-y-2">
        <h4 className="text-[10px] font-bold uppercase tracking-wider text-muted-foreground">Active Rivals</h4>
        <div className="space-y-2">
          {rivals.slice(0, 5).map((rival, i) => (
            <div 
              key={rival.id} 
              className="flex items-center justify-between p-2 rounded-lg bg-background/50 hover:bg-background transition-colors"
            >
              <div className="flex items-center gap-2">
                <span className="text-xs font-mono text-muted-foreground">#{i + 1}</span>
                <div>
                  <p className="text-xs font-bold">{rival.name}</p>
                  <p className="text-[9px] text-muted-foreground uppercase">{rival.archetype}</p>
                </div>
              </div>
              <div className="text-right">
                <p className="text-xs font-mono font-bold">{formatMoney(rival.cash)}</p>
                <p className="text-[9px] text-muted-foreground">{rival.prestige} prestige</p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

import React, { useMemo } from 'react';
import { useGameStore } from '@/store/gameStore';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Heatmap } from '@/components/shared/Heatmap';
import { cn } from '@/lib/utils';
import { TrendingUp, TrendingDown, Activity } from 'lucide-react';

interface MarketTrendsHeatmapProps {
  className?: string;
}

const GENRES = ['Action', 'Comedy', 'Drama', 'Horror', 'Romance', 'Sci-Fi', 'Thriller'];
const QUARTERS = ['Q1', 'Q2', 'Q3', 'Q4'];

export const MarketTrendsHeatmap: React.FC<MarketTrendsHeatmapProps> = ({ className }) => {
  const gameState = useGameStore(s => s.gameState);

  // Generate heatmap data based on genre trends and market saturation
  const heatmapData = useMemo(() => {
    if (!gameState) {
      return [];
    }
    const { trends = [] } = gameState.market;
    const marketSentiment = gameState.finance?.marketState?.sentiment || 50;
    const { genrePopularity = {} } = gameState.studio?.culture || {};

    const data: { id: string; row: string; col: string; value: number; tooltip: string }[] = [];

    GENRES.forEach(genre => {
      QUARTERS.forEach(quarter => {
        // Calculate opportunity score based on multiple factors
        const trendData = trends.find(t => t.genre.toLowerCase() === genre.toLowerCase());
        const popularity = genrePopularity[genre as keyof typeof genrePopularity] || 50;

        // Count active projects in this genre
        const genreProjects = Object.values(gameState.entities.projects).filter(
          p => p.genre.toLowerCase() === genre.toLowerCase() &&
               p.state !== 'archived' && p.state !== 'post_release'
        ).length;

        // Calculate saturation (how crowded the market is)
        const rivalProjects = Object.values(gameState.entities.rivals).reduce(
          (sum, rival) => sum + Object.values(rival.projects || {})
            .filter(p => p.genre?.toLowerCase() === genre.toLowerCase()).length,
          0
        );
        const saturation = Math.min(100, (genreProjects + rivalProjects) * 10);

        // Combine factors for opportunity score
        const heat = trendData?.heat || 50;
        const opportunity = Math.max(0, Math.min(100,
          (popularity * 0.3) + (heat * 0.4) - (saturation * 0.3) + (marketSentiment * 0.1)
        ));

        let status = 'Stable';
        if (opportunity > 70) status = 'Hot';
        else if (opportunity > 50) status = 'Growing';
        else if (opportunity < 30) status = 'Cooling';
        else if (saturation > 70) status = 'Oversaturated';

        data.push({
          id: `${genre}-${quarter}`,
          row: genre,
          col: quarter,
          value: opportunity,
          tooltip: `${genre} in ${quarter}: ${status} (${Math.round(opportunity)}% opportunity)\nActive Projects: ${genreProjects + rivalProjects}\nPopularity: ${popularity}%`,
        });
      });
    });

    return data;
  }, [gameState]);

  // Find hot genres
  const hotGenres = useMemo(() => {
    const avgByGenre: Record<string, number> = {};
    GENRES.forEach(genre => {
      const genreData = heatmapData.filter(d => d.row === genre);
      avgByGenre[genre] = genreData.reduce((sum, d) => sum + d.value, 0) / (genreData.length || 1);
    });

    return Object.entries(avgByGenre)
      .sort((a, b) => b[1] - a[1])
      .slice(0, 3);
  }, [heatmapData]);

  // Find cooling genres
  const coolingGenres = useMemo(() => {
    const avgByGenre: Record<string, number> = {};
    GENRES.forEach(genre => {
      const genreData = heatmapData.filter(d => d.row === genre);
      avgByGenre[genre] = genreData.reduce((sum, d) => sum + d.value, 0) / (genreData.length || 1);
    });

    return Object.entries(avgByGenre)
      .sort((a, b) => a[1] - b[1])
      .slice(0, 3);
  }, [heatmapData]);

  if (!gameState) return null;

  return (
    <Card className={cn("border-border/50", className)}>
      <CardHeader className="pb-3">
        <div className="flex items-center justify-between">
          <CardTitle className="text-xs font-black uppercase tracking-wider flex items-center gap-2">
            <Activity className="w-4 h-4" />
            Genre Opportunity Matrix
          </CardTitle>
        </div>
      </CardHeader>

      <CardContent className="space-y-4">
        <p className="text-[10px] text-muted-foreground">
          Heatmap shows genre opportunity scores by quarter. Darker colors indicate better opportunities.
        </p>

        <Heatmap
          data={heatmapData}
          rows={GENRES}
          cols={QUARTERS}
          colorScale="sequential"
          cellSize="md"
          className="w-full"
        />

        {/* Trending Summary */}
        <div className="grid grid-cols-2 gap-3 pt-3 border-t border-border/30">
          <div>
            <div className="flex items-center gap-1.5 mb-2">
              <TrendingUp className="w-3.5 h-3.5 text-emerald-400" />
              <span className="text-[10px] font-bold uppercase text-emerald-400">Hot Genres</span>
            </div>
            <div className="space-y-1">
              {hotGenres.map(([genre, score]) => (
                <div key={genre} className="flex items-center justify-between text-[10px]">
                  <span className="text-muted-foreground">{genre}</span>
                  <span className="font-mono font-bold text-emerald-400">{Math.round(score)}%</span>
                </div>
              ))}
            </div>
          </div>

          <div>
            <div className="flex items-center gap-1.5 mb-2">
              <TrendingDown className="w-3.5 h-3.5 text-red-400" />
              <span className="text-[10px] font-bold uppercase text-red-400">Cooling</span>
            </div>
            <div className="space-y-1">
              {coolingGenres.map(([genre, score]) => (
                <div key={genre} className="flex items-center justify-between text-[10px]">
                  <span className="text-muted-foreground">{genre}</span>
                  <span className="font-mono font-bold text-red-400">{Math.round(score)}%</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </CardContent>
    </Card>
  );
};

