function cn(...classes: string[]) {
  return classes.filter(Boolean).join(' ');
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useGameStore } from '@/store/gameStore';
import { useUIStore } from '@/store/uiStore';
import { Project } from '@/engine/types';
import { Button } from '@/components/ui/button';
import { Gavel, Users, TrendingUp, Clock } from 'lucide-react';
import { generateFestivalBid } from '@/engine/systems/ai/AgentBrain';
import { RandomGenerator } from '@/engine/utils/rng';

/**
 * FestivalMarketModal: The "Gavel Auction" live bidding interface.
 * Simulates real-time (simulated) bidding between the player and AI rivals.
 */
export const FestivalMarketModal: React.FC = () => {
  const gameState = useGameStore(s => s.gameState);
  const studioFinance = useGameStore(s => s.finance);
  const addProject = useGameStore(s => s.addProject);
  const addFunds = useGameStore(s => s.addFunds);

  const { activeModal, resolveCurrentModal } = useUIStore();

  const project = activeModal?.payload?.project as Project;
  const [currentBid, setCurrentBid] = useState(Math.round(project?.budget * 0.8 || 0));
  const [highestBidderId, setHighestBidderId] = useState<string | 'PLAYER' | null>(null);
  const [highestBidderName, setHighestBidderName] = useState<string>('Opening Floor');
  const [timeLeft, setTimeLeft] = useState(10); // Ticks until gavel falls
  const [isResolved, setIsResolved] = useState(false);

  // Refs so the interval always reads the latest values without re-creating on every state change
  const currentBidRef = useRef(currentBid);
  const highestBidderIdRef = useRef(highestBidderId);
  const resolveRef = useRef(resolveCurrentModal);
  const isMounted = useRef(true);

  useEffect(() => { currentBidRef.current = currentBid; }, [currentBid]);
  useEffect(() => { highestBidderIdRef.current = highestBidderId; }, [highestBidderId]);
  useEffect(() => { resolveRef.current = resolveCurrentModal; }, [resolveCurrentModal]);
  useEffect(() => {
    isMounted.current = true;
    return () => { isMounted.current = false; };
  }, []);

  // Hoisted above useEffect so the dep array is satisfied without re-creation churn
  const handleFinalize = useCallback(() => {
    setIsResolved(true);
    const bidderId = highestBidderIdRef.current;
    const bid = currentBidRef.current;

    if (!bidderId || !project) {
      resolveRef.current();
      return;
    }

    // Dispatch victory impact
    if (bidderId === 'PLAYER') {
      addProject({
        ...project,
        state: 'released',
        isAcquired: true,
        acquisitionCost: bid,
      });
      addFunds(-bid);
    }

    // Wait 2 seconds then close — only if still mounted
    setTimeout(() => {
      if (isMounted.current) resolveRef.current();
    }, 2000);
  }, [project, addProject, addFunds]);

  // AI Bidding Logic (Simulated ticks)
  useEffect(() => {
    if (isResolved || !project || !gameState) return;

    const timer = setInterval(() => {
      setTimeLeft(prev => {
        if (prev <= 1) {
          clearInterval(timer);
          handleFinalize();
          return 0;
        }
        return prev - 1;
      });

      // 🎭 UI Simulation: We use a non-deterministic local RNG for the "feeling" of a live auction.
      // The actual acquisition is committed to the state only on win.
      const localRng = new RandomGenerator(Date.now());
      const rivals = gameState.entities.rivals;
      // Read latest bid/bidder from refs — avoids stale closure on each interval tick
      const latestBid = currentBidRef.current;
      const latestBidderId = highestBidderIdRef.current;

      Object.values(rivals).forEach(rival => {
        if (rival.id === latestBidderId) return;

        // Determine if this rival wants to bid
        const potentialBid = generateFestivalBid(rival, project, localRng);
        const nextIncrementalBid = Math.round(latestBid * 1.05);

        if (potentialBid && potentialBid >= nextIncrementalBid && rival.cash >= nextIncrementalBid) {
          // AI Bids! - Add some jitter to make it feel more human/rivalrous
          if (localRng.next() < 0.25) {
            setCurrentBid(nextIncrementalBid);
            setHighestBidderId(rival.id);
            setHighestBidderName(rival.name);
            setTimeLeft(5); // Reset timer on new bid
          }
        }
      });
    }, 1500);

    return () => clearInterval(timer);
  }, [isResolved, project, gameState, handleFinalize, setCurrentBid, setHighestBidderId, setHighestBidderName, setTimeLeft]);

  const handlePlayerBid = () => {
    if (!gameState) return;
    const nextBid = Math.round(currentBidRef.current * 1.05);
    if (studioFinance.cash < nextBid) return;

    setCurrentBid(nextBid);
    setHighestBidderId('PLAYER');
    setHighestBidderName(gameState.studio.name);
    setTimeLeft(5); // Reset timer
  };

  if (!project || !gameState) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-black/80 backdrop-blur-md animate-in fade-in duration-300">
      <div className="relative w-full max-w-2xl bg-slate-950 border border-slate-800 rounded-2xl shadow-2xl overflow-hidden">
        {/* Header */}
        <div className="p-6 border-b border-slate-800 bg-gradient-to-r from-amber-500/10 to-transparent">
          <div className="flex items-center gap-3 mb-2">
            <Gavel className="w-5 h-5 text-amber-500" />
            <span className="text-[10px] font-black uppercase tracking-[0.2em] text-amber-500">Live Festival Auction</span>
          </div>
          <h2 className="text-3xl font-display font-black tracking-tight text-white line-clamp-1">{project.title}</h2>
          <p className="text-slate-400 text-xs mt-1 italic">{project.genre} • quality: {project.reviewScore}%</p>
        </div>

        {/* Main Auction Block */}
        <div className="p-8 flex flex-col items-center justify-center text-center">
          <div className="mb-8">
            <div className="text-[10px] uppercase font-black tracking-widest text-slate-500 mb-2">Current High Bid</div>
            <div className="text-6xl font-display font-black text-white tabular-nums tracking-tighter">
              ${(currentBid / 1000000).toFixed(2)}M
            </div>
            <div className="flex items-center justify-center gap-2 mt-3 p-2 bg-slate-900 rounded-full border border-slate-800">
              <Users className="w-3.5 h-3.5 text-slate-400" />
              <span className={`text-xs font-bold ${highestBidderId === 'PLAYER' ? 'text-green-400' : 'text-slate-200'}`}>
                {highestBidderName}
              </span>
            </div>
          </div>

          {/* Progress Bar / Timer */}
          <div className="w-full max-w-md bg-slate-900 h-1.5 rounded-full overflow-hidden mb-8 border border-slate-800">
             <div 
               className={`h-full transition-all duration-1000 ease-linear ${timeLeft < 3 ? 'bg-red-500' : 'bg-amber-500'}`}
               style={{ width: `${(timeLeft / 10) * 100}%` }}
             />
          </div>

          {isResolved ? (
            <div className="py-6 animate-bounce">
              <span className="text-4xl font-display font-black text-amber-500 uppercase italic tracking-tighter">
                Sold!
              </span>
            </div>
          ) : (
            <div className="flex flex-col gap-4 w-full max-w-sm">
              <Button 
                size="lg" 
                onClick={handlePlayerBid}
                disabled={studioFinance.cash < currentBid * 1.05}
                className="h-16 text-lg font-black uppercase tracking-wider bg-white text-black hover:bg-slate-200 transition-all shadow-[0_0_20px_rgba(255,255,255,0.1)]"
              >
                <TrendingUp className="w-5 h-5 mr-2" />
                Bid ${( (currentBid * 1.05) / 1000000).toFixed(2)}M
              </Button>
              <div className="text-[10px] text-slate-500 uppercase tracking-widest font-bold">
                Your Cash: ${(studioFinance.cash / 1000000).toFixed(1)}M
              </div>
            </div>
          )}
        </div>

        {/* Footer / Info */}
        <div className="p-4 bg-slate-900/50 border-t border-slate-800 flex justify-between items-center text-[9px] uppercase font-black tracking-widest text-slate-500">
          <div className="flex items-center gap-2">
            <Clock className="w-3 h-3" />
            <span>Time Remaining: {timeLeft}s</span>
          </div>
          <div>Location: Park City, Utah</div>
        </div>
      </div>
    </div>
  );
};

import { useState } from 'react';
import { useUIStore } from '@/store/uiStore';
import { useGameStore } from '@/store/gameStore';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Package, DollarSign, Star, Users, Calendar, Building2, TrendingUp } from 'lucide-react';
import { TalentNameLink } from '@/components/shared/TalentNameLink';
import { formatMoney } from '@/engine/utils';
import type { Opportunity, Talent } from '@/engine/types';

interface PackageDetailModalProps {
  packageId?: string;
}

export const PackageDetailModal = ({ packageId: propPackageId }: PackageDetailModalProps) => {
  const { resolveCurrentModal, activeModal } = useUIStore();
  const gameState = useGameStore(s => s.gameState);

  const [bidAmount, setBidAmount] = useState<number>(0);

  const packageId = propPackageId || (activeModal?.payload as any)?.packageId;
  const packageData = gameState?.market?.opportunities?.find(o => o.id === packageId);
  const packageTalents = (packageData?.attachedTalentIds || [])
    .map(id => gameState?.entities.talents?.[id])
    .filter(Boolean) as Talent[];

  const handleBid = () => {
    if (!packageData || bidAmount <= 0) return;

    // Implement bidding logic - this would need a proper store action
    // For now, just close the modal
    resolveCurrentModal();
  };

  const handleClose = () => {
    resolveCurrentModal();
  };

  if (!packageData) return null;

  return (
    <Dialog open={true} onOpenChange={handleClose}>
      <DialogContent className="max-w-3xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Package className="h-5 w-5" />
            {packageData.title}
          </DialogTitle>
          <DialogDescription>
            Talent package details and bidding information
          </DialogDescription>
        </DialogHeader>

        <div className="space-y-6 py-4">
          {/* Package Overview */}
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <div className="flex items-center gap-2 text-sm text-muted-foreground">
                <DollarSign className="h-4 w-4" />
                Cost to Acquire
              </div>
              <p className="text-2xl font-bold">{formatMoney(packageData.costToAcquire)}</p>
            </div>
            <div className="space-y-2">
              <div className="flex items-center gap-2 text-sm text-muted-foreground">
                <Star className="h-4 w-4" />
                Quality Bonus
              </div>
              <p className="text-2xl font-bold">+{packageData.qualityBonus || 0}</p>
            </div>
            <div className="space-y-2">
              <div className="flex items-center gap-2 text-sm text-muted-foreground">
                <Calendar className="h-4 w-4" />
                Weeks Until Expiry
              </div>
              <p className="text-2xl font-bold">{packageData.weeksUntilExpiry || 0}</p>
            </div>
            <div className="space-y-2">
              <div className="flex items-center gap-2 text-sm text-muted-foreground">
                <Building2 className="h-4 w-4" />
                Origin
              </div>
              <Badge variant="outline">{packageData.origin}</Badge>
            </div>
          </div>

          {/* Package Description */}
          <div className="space-y-2">
            <h3 className="font-semibold">Description</h3>
            <p className="text-sm text-muted-foreground">{packageData.flavor}</p>
          </div>

          {/* Attached Talent */}
          <div className="space-y-2">
            <h3 className="font-semibold flex items-center gap-2">
              <Users className="h-4 w-4" />
              Included Talent
            </h3>
            {packageTalents.length === 0 ? (
              <p className="text-sm text-muted-foreground">No talent attached to this package</p>
            ) : (
              <div className="flex flex-wrap gap-2">
                {packageTalents.map(talent => (
                  <Badge key={talent.id} variant="outline" className="text-sm bg-primary/10">
                    <TalentNameLink talentId={talent.id} name={talent.name} />
                    <span className="ml-1 text-muted-foreground">• Tier {talent.tier}</span>
                  </Badge>
                ))}
              </div>
            )}
          </div>

          {/* Bidding Section */}
          <div className="space-y-4 border-t pt-4">
            <h3 className="font-semibold flex items-center gap-2">
              <TrendingUp className="h-4 w-4" />
              Place Bid
            </h3>

            <div className="space-y-2">
              <label className="text-sm font-medium">Bid Amount</label>
              <div className="flex gap-2">
                <input
                  type="number"
                  value={bidAmount}
                  onChange={(e) => setBidAmount(Number(e.target.value))}
                  className="flex-1 px-3 py-2 border rounded-md"
                  placeholder="Enter bid amount"
                  min={0}
                  step={100000}
                />
                <Button 
                  variant="outline"
                  onClick={() => setBidAmount(packageData.costToAcquire * 1.1)}
                >
                  Min +10%
                </Button>
              </div>
              <p className="text-xs text-muted-foreground">
                Current asking price: {formatMoney(packageData.costToAcquire)}
              </p>
            </div>

            <div className="space-y-2">
              <label className="text-sm font-medium">Bid Terms</label>
              <textarea
                className="w-full px-3 py-2 border rounded-md"
                rows={3}
                placeholder="Enter any special terms or conditions..."
              />
            </div>
          </div>

          {/* Bid History */}
          {packageData.bidHistory && packageData.bidHistory.length > 0 && (
            <div className="space-y-2 border-t pt-4">
              <h3 className="font-semibold">Bid History</h3>
              <div className="space-y-1">
                {packageData.bidHistory.map((bid, index) => (
                  <div key={index} className="flex justify-between text-sm">
                    <span className="text-muted-foreground">
                      {bid.rivalId === 'PLAYER' ? 'Your Studio' : bid.rivalId} (Week {bid.week})
                    </span>
                    <span className="font-medium">{formatMoney(bid.amount)}</span>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>

        <DialogFooter>
          <Button variant="outline" onClick={handleClose}>
            Close
          </Button>
          <Button
            onClick={handleBid}
            disabled={bidAmount <= 0}
          >
            Place Bid ({formatMoney(bidAmount)})
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
};

export default PackageDetailModal;

import { useState, useEffect, useRef } from 'react';
import { useGameStore } from '@/store/gameStore';
import { useUIStore } from '@/store/uiStore';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import type { ProjectContractType } from '@/engine/types';
import { calculateFitScore } from '@/engine/systems/buyers';
import { RandomGenerator } from '@/engine/utils/rng';

export const PitchProjectModal = () => {
  const { showPitchProject, closePitchProject, pitchingProjectId } = useUIStore();
  const gameState = useGameStore(s => s.gameState);
  const pitchProject = useGameStore(s => s.pitchProject);

  const [selectedBuyerId, setSelectedBuyerId] = useState<string>('');
  const [selectedContract, setSelectedContract] = useState<ProjectContractType>('upfront');
  const [feedback, setFeedback] = useState<string | null>(null);
  const closeTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Clear any pending close timer on unmount
  useEffect(() => () => {
    if (closeTimerRef.current) clearTimeout(closeTimerRef.current);
  }, []);

  if (!gameState || !pitchingProjectId) return null;

  const project = gameState?.entities?.projects[pitchingProjectId];
  if (!project) return null;

  const handlePitch = async () => {
    setFeedback(null);
    if (!selectedBuyerId) return;

    const success = await pitchProject(project.id, selectedBuyerId, selectedContract);

    if (success) {
      setFeedback('Pitch Successful! Project picked up.');
      closeTimerRef.current = setTimeout(() => {
        setFeedback(null);
        setSelectedBuyerId('');
        closePitchProject();
      }, 1500);
    } else {
      setFeedback('Pitch Failed. They passed on the project.');
    }
  };

  const handleClose = () => {
    if (closeTimerRef.current) {
      clearTimeout(closeTimerRef.current);
      closeTimerRef.current = null;
    }
    setFeedback(null);
    setSelectedBuyerId('');
    closePitchProject();
  };

  return (
    <Dialog open={showPitchProject} onOpenChange={handleClose}>
      <DialogContent className="max-w-2xl">
        <DialogHeader>
          <DialogTitle>Pitch Project: {project.title}</DialogTitle>
          <DialogDescription>
            Select a network or streamer to pitch this series to, and propose a contract structure.
          </DialogDescription>
        </DialogHeader>

        <div className="grid grid-cols-2 gap-6 py-4">
          <div className="space-y-4">
            <h4 className="font-semibold text-sm text-muted-foreground uppercase">1. Select Buyer</h4>
            <div className="space-y-2">
              {gameState.market.buyers.map(buyer => {
                const rng = new RandomGenerator(gameState.gameSeed + gameState.week);
                const fitScore = calculateFitScore(project, buyer, gameState.week, gameState.entities.projects, rng);
                return (
                  <button
                    key={buyer.id}
                    onClick={() => setSelectedBuyerId(buyer.id)}
                    aria-pressed={selectedBuyerId === buyer.id}
                    className={`w-full text-left p-3 rounded border transition-colors ${
                      selectedBuyerId === buyer.id
                        ? 'border-primary bg-primary/10'
                        : 'border-border bg-card hover:bg-accent'
                    }`}
                  >
                    <div className="flex justify-between items-center mb-1">
                      <span className="font-semibold text-sm">{buyer.name}</span>
                      <Badge variant="outline" className="text-[10px]">{buyer.archetype}</Badge>
                    </div>
                    {buyer.currentMandate && (
                      <p className="text-xs text-muted-foreground">
                        Mandate: <span className="text-foreground">{buyer.currentMandate.type.replace('_', ' ')}</span>
                      </p>
                    )}
                    <p className="text-xs text-muted-foreground mt-1">Est. Fit: {Math.round(fitScore)}/100</p>
                  </button>
                );
              })}
            </div>
          </div>

          <div className="space-y-4">
            <h4 className="font-semibold text-sm text-muted-foreground uppercase">2. Deal Structure</h4>
            <div className="space-y-2">
              <button
                onClick={() => setSelectedContract('upfront')}
                aria-pressed={selectedContract === 'upfront'}
                className={`w-full text-left p-3 rounded border transition-colors ${
                  selectedContract === 'upfront'
                    ? 'border-primary bg-primary/10'
                    : 'border-border bg-card hover:bg-accent'
                }`}
              >
                <span className="font-semibold text-sm block">High Upfront Fee</span>
                <p className="text-xs text-muted-foreground mt-1">
                  Buyer fully funds production (0 weekly cost). Studio retains 0% backend. Harder to sell.
                </p>
              </button>

              <button
                onClick={() => setSelectedContract('deficit')}
                aria-pressed={selectedContract === 'deficit'}
                className={`w-full text-left p-3 rounded border transition-colors ${
                  selectedContract === 'deficit'
                    ? 'border-primary bg-primary/10'
                    : 'border-border bg-card hover:bg-accent'
                }`}
              >
                <span className="font-semibold text-sm block">Deficit Financing</span>
                <p className="text-xs text-muted-foreground mt-1">
                  Studio pays 30% of production costs. Studio retains 100% backend. Easier to sell.
                </p>
              </button>
            </div>

            <div className="pt-6">
              <Button
                onClick={handlePitch}
                disabled={!selectedBuyerId || !!feedback}
                className="w-full"
              >
                Pitch Project
              </Button>
              {feedback && (
                <p className={`mt-4 text-center text-sm font-semibold ${feedback.includes('Failed') ? 'text-destructive' : 'text-success'}`}>
                  {feedback}
                </p>
              )}
            </div>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
};

import { useMemo, useState } from 'react';
import { useGameStore } from '@/store/gameStore';
