import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
  Search,
  Film,
  Users,
  TrendingUp,
  DollarSign,
  Briefcase,
  Globe,
  LayoutDashboard,
  ArrowRight,
  Clock,
  Sparkles,
  AlertTriangle,
  Activity,
  Zap,
  Flame,
} from 'lucide-react';
import { cn } from '@/lib/utils';
import { tokens } from '@/lib/tokens';
import { transitions } from '@/lib/animations';
import { useUIStore } from '@/store/uiStore';
import { useGameStore } from '@/store/gameStore';

interface CommandItem {
  id: string;
  title: string;
  subtitle?: string;
  icon: React.ComponentType<{ className?: string; size?: number | string }>;
  shortcut?: string;
  action: () => void;
  section: string;
  keywords?: string[];
}

interface CommandPaletteProps {
  /** Is palette open */
  isOpen: boolean;
  /** Close handler */
  onClose: () => void;
}

/**
 * CommandPalette - Quick navigation and action center
 * 
 * Provides keyboard-driven access to:
 * - Hub navigation (Cmd+1, Cmd+2, etc.)
 * - Recent actions
 * - Project/talent search
 * - Common actions (new project, etc.)
 */
export const CommandPalette: React.FC<CommandPaletteProps> = ({
  isOpen,
  onClose,
}) => {
  const [query, setQuery] = useState('');
  const [selectedIndex, setSelectedIndex] = useState(0);
  const { openCreateProject, setActiveHub, setActiveSubTab } = useUIStore();
  const doAdvanceWeek = useGameStore((s) => s.doAdvanceWeek);

  // Build command list
  const commands: CommandItem[] = React.useMemo(() => {
    const list: CommandItem[] = [
      // Navigation
      {
        id: 'nav-hq',
        title: 'Studio HQ',
        subtitle: 'Overview, operations, strategy',
        icon: LayoutDashboard,
        shortcut: '⌘1',
        action: () => setActiveHub('hq'),
        section: 'Navigation',
      },
      {
        id: 'nav-production',
        title: 'Production',
        subtitle: 'Slate, development, distribution',
        icon: Film,
        shortcut: '⌘2',
        action: () => setActiveHub('production'),
        section: 'Navigation',
      },
      {
        id: 'nav-talent',
        title: 'Talent & Deals',
        subtitle: 'Roster, marketplace, agencies',
        icon: Users,
        shortcut: '⌘3',
        action: () => setActiveHub('talent'),
        section: 'Navigation',
      },
      {
        id: 'nav-intelligence',
        title: 'Intelligence',
        subtitle: 'Rivals, awards, market, financials',
        icon: Globe,
        shortcut: '⌘4',
        action: () => setActiveHub('intelligence'),
        section: 'Navigation',
      },
      // Actions
      {
        id: 'action-new-project',
        title: 'New Project',
        subtitle: 'Create a new film or TV project',
        icon: Sparkles,
        shortcut: '⌘N',
        action: () => openCreateProject(),
        section: 'Actions',
      },
      {
        id: 'action-week',
        title: 'Advance Week',
        subtitle: 'Progress to next production week',
        icon: Clock,
        action: () => { doAdvanceWeek(); },
        section: 'Actions',
      },
      // Crisis Management
      {
        id: 'crisis-dashboard',
        title: 'Crisis Dashboard',
        subtitle: 'View all active crises and issues',
        icon: AlertTriangle,
        shortcut: '⌘⇧C',
        action: () => {
          setActiveHub('hq');
          setActiveSubTab('operations');
        },
        section: 'Crisis Management',
        keywords: ['emergency', 'problems', 'issues', 'alerts'],
      },
      {
        id: 'greenlight-queue',
        title: 'Greenlight Queue',
        subtitle: 'Review projects awaiting approval',
        icon: Zap,
        action: () => {
          setActiveHub('production');
          setActiveSubTab('slate');
        },
        section: 'Crisis Management',
        keywords: ['approve', 'projects', 'slate'],
      },
      // Intelligence Views
      {
        id: 'market-trends',
        title: 'Market Trends',
        subtitle: 'View genre trends and market sentiment',
        icon: TrendingUp,
        action: () => {
          setActiveHub('intelligence');
          setActiveSubTab('market');
        },
        section: 'Intelligence',
        keywords: ['genres', 'trends', 'market', 'analysis'],
      },
      {
        id: 'studio-health',
        title: 'Studio Health',
        subtitle: 'Check overall studio performance metrics',
        icon: Activity,
        action: () => {
          setActiveHub('hq');
          setActiveSubTab('overview');
        },
        section: 'Intelligence',
        keywords: ['health', 'metrics', 'performance', 'dashboard'],
      },
      // Talent Views  
      {
        id: 'talent-morale',
        title: 'Talent Morale',
        subtitle: 'Check roster satisfaction levels',
        icon: Users,
        action: () => {
          setActiveHub('talent');
          setActiveSubTab('roster');
        },
        section: 'Talent',
        keywords: ['morale', 'happiness', 'satisfaction', 'roster'],
      },
      {
        id: 'deal-history',
        title: 'Deal History',
        subtitle: 'View negotiation history and offers',
        icon: Briefcase,
        action: () => {
          setActiveHub('talent');
          setActiveSubTab('negotiations');
        },
        section: 'Talent',
        keywords: ['offers', 'negotiations', 'deals', 'history'],
      },
      // Financial Views
      {
        id: 'budget-burn',
        title: 'Budget Burn Rate',
        subtitle: 'Monitor production spending vs planned',
        icon: Flame,
        action: () => {
          setActiveHub('production');
          setActiveSubTab('development');
        },
        section: 'Finance',
        keywords: ['budget', 'spending', 'overrun', 'costs'],
      },
      {
        id: 'cash-flow',
        title: 'Cash Flow',
        subtitle: 'View revenue and expense trends',
        icon: DollarSign,
        action: () => {
          setActiveHub('intelligence');
          setActiveSubTab('financials');
        },
        section: 'Finance',
        keywords: ['cash', 'revenue', 'expenses', 'financials'],
      },
    ];

    return list;
  }, [setActiveHub, setActiveSubTab, openCreateProject, doAdvanceWeek]);

  // Filter commands based on query
  const filteredCommands = React.useMemo(() => {
    if (!query) return commands;
    const lowerQuery = query.toLowerCase();
    return commands.filter(
      (cmd) =>
        cmd.title.toLowerCase().includes(lowerQuery) ||
        cmd.subtitle?.toLowerCase().includes(lowerQuery) ||
        cmd.section.toLowerCase().includes(lowerQuery) ||
        cmd.keywords?.some((k) => k.toLowerCase().includes(lowerQuery))
    );
  }, [commands, query]);

  // Group commands by section
  const groupedCommands = React.useMemo(() => {
    const groups: Record<string, CommandItem[]> = {};
    filteredCommands.forEach((cmd) => {
      if (!groups[cmd.section]) groups[cmd.section] = [];
      groups[cmd.section].push(cmd);
    });
    return groups;
  }, [filteredCommands]);

  // Reset selection when query changes
  useEffect(() => {
    setSelectedIndex(0);
  }, [query]);

  // Keyboard navigation
  useEffect(() => {
    if (!isOpen) return;

    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        onClose();
        return;
      }

      if (e.key === 'ArrowDown') {
        e.preventDefault();
        setSelectedIndex((prev) =>
          Math.min(prev + 1, filteredCommands.length - 1)
        );
      } else if (e.key === 'ArrowUp') {
        e.preventDefault();
        setSelectedIndex((prev) => Math.max(prev - 1, 0));
      } else if (e.key === 'Enter') {
        e.preventDefault();
        const selected = filteredCommands[selectedIndex];
        if (selected) {
          selected.action();
          onClose();
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isOpen, onClose, filteredCommands, selectedIndex]);

  // Focus input on open
  useEffect(() => {
    if (isOpen) {
      setQuery('');
      setSelectedIndex(0);
    }
  }, [isOpen]);

  // Get selected item from flat list
  const flatCommands = Object.values(groupedCommands).flat();

  if (!isOpen) return null;

  return (
    <AnimatePresence>
      {isOpen && (
        <>
          {/* Backdrop */}
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50"
            onClick={onClose}
          />

          {/* Palette */}
          <motion.div
            initial={{ opacity: 0, scale: 0.95, y: -20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95, y: -20 }}
            transition={{ ...transitions.spring }}
            className="fixed top-[20%] left-1/2 -translate-x-1/2 w-full max-w-2xl z-50"
          >
            <div className="bg-card/95 backdrop-blur-2xl border border-white/10 rounded-xl shadow-2xl overflow-hidden">
              {/* Search header */}
              <div className="flex items-center gap-3 px-4 py-4 border-b border-white/5">
                <Search className="w-5 h-5 text-muted-foreground" />
                <input
                  type="text"
                  value={query}
                  onChange={(e) => setQuery(e.target.value)}
                  placeholder="Search commands, navigate, or run actions..."
                  className="flex-1 bg-transparent border-none outline-none text-sm placeholder:text-muted-foreground"
                  autoFocus
                />
                <kbd className="px-2 py-1 bg-muted rounded text-xs text-muted-foreground">
                  ESC
                </kbd>
              </div>

              {/* Results */}
              <div className="max-h-[400px] overflow-y-auto py-2">
                {flatCommands.length === 0 ? (
                  <div className="px-4 py-8 text-center text-muted-foreground">
                    <p>No commands found</p>
                    <p className="text-xs mt-1">
                      Try a different search term
                    </p>
                  </div>
                ) : (
                  Object.entries(groupedCommands).map(([section, items]) => (
                    <div key={section}>
                      <div className="px-4 py-2 text-xs font-semibold text-muted-foreground uppercase tracking-wider">
                        {section}
                      </div>
                      {items.map((item) => {
                        const flatIdx = flatCommands.indexOf(item);
                        const isSelected = flatIdx === selectedIndex;
                        const Icon = item.icon;

                        return (
                          <button
                            key={item.id}
                            onClick={() => {
                              item.action();
                              onClose();
                            }}
                            onMouseEnter={() => setSelectedIndex(flatIdx)}
                            className={cn(
                              'w-full flex items-center gap-3 px-4 py-3 text-left',
                              'hover:bg-white/5',
                              isSelected && 'bg-white/10',
                              tokens.transition.fast
                            )}
                          >
                            <div className="w-8 h-8 rounded-lg bg-primary/10 flex items-center justify-center shrink-0">
                              <Icon className="w-4 h-4 text-primary" />
                            </div>
                            <div className="flex-1 min-w-0">
                              <p className="text-sm font-medium text-foreground">
                                {item.title}
                              </p>
                              {item.subtitle && (
                                <p className="text-xs text-muted-foreground truncate">
                                  {item.subtitle}
                                </p>
                              )}
                            </div>
                            {item.shortcut && (
                              <kbd className="px-2 py-1 bg-muted rounded text-xs text-muted-foreground shrink-0">
                                {item.shortcut}
                              </kbd>
                            )}
                          </button>
                        );
                      })}
                    </div>
                  ))
                )}
              </div>

              {/* Footer */}
              <div className="px-4 py-3 bg-muted/30 border-t border-white/5 flex items-center justify-between text-xs text-muted-foreground">
                <div className="flex items-center gap-4">
                  <span className="flex items-center gap-1">
                    <ArrowRight className="w-3 h-3" /> to select
                  </span>
                  <span className="flex items-center gap-1">
                    <kbd className="px-1.5 py-0.5 bg-muted rounded text-[10px]">
                      ↵
                    </kbd>{' '}
                    to run
                  </span>
                </div>
                <span>{flatCommands.length} commands</span>
              </div>
            </div>
          </motion.div>
        </>
      )}
    </AnimatePresence>
  );
};

/**
 * Hook to manage command palette state
 */
export const useCommandPalette = () => {
  const [isOpen, setIsOpen] = useState(false);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Cmd+K or Ctrl+K
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        setIsOpen((prev) => !prev);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  return {
    isOpen,
    open: () => setIsOpen(true),
    close: () => setIsOpen(false),
    toggle: () => setIsOpen((prev) => !prev),
  };
};

export default CommandPalette;

import React, { useMemo } from 'react';
import { useGameStore } from '@/store/gameStore';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { formatMoney } from '@/engine/utils';
import { cn } from '@/lib/utils';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { Wallet, AlertTriangle } from 'lucide-react';

interface ResourceAllocationProps {
  className?: string;
}

export const ResourceAllocation: React.FC<ResourceAllocationProps> = ({ className }) => {
  const gameState = useGameStore(s => s.gameState);

  const { projects, finance } = useMemo(() => {
    if (!gameState) {
      return { projects: [], finance: { cash: 0 } };
    }
    const projects = Object.values(gameState.entities.projects);
    return { projects, finance: gameState.finance };
  }, [gameState]);

  const allocationData = useMemo(() => {
    const activeProjects = projects.filter(p =>
      p.state === 'production' || p.state === 'development' || p.state === 'marketing'
    );

    return activeProjects.map(p => ({
      name: p.title.length > 15 ? p.title.slice(0, 15) + '...' : p.title,
      fullName: p.title,
      weeklyCost: p.weeklyCost || 0,
      state: p.state,
      budget: p.budget,
      accumulated: p.accumulatedCost || 0,
      percentUsed: p.budget > 0 ? ((p.accumulatedCost || 0) / p.budget) * 100 : 0,
    }));
  }, [projects]);

  const totalWeeklyBurn = allocationData.reduce((sum, p) => sum + p.weeklyCost, 0);
  const runway = totalWeeklyBurn > 0 ? finance.cash / totalWeeklyBurn : 999;

  // Group by state for stacked view
  const stateGroups = useMemo(() => {
    const groups: Record<string, typeof allocationData> = {
      development: [],
      production: [],
      marketing: [],
    };

    allocationData.forEach(p => {
      if (groups[p.state]) {
        groups[p.state].push(p);
      }
    });

    return groups;
  }, [allocationData]);

  if (!gameState) return null;

  const isOverallocated = runway < 8;
  const isCritical = runway < 4;

  return (
    <Card className={cn("border-border/50", className)}>
      <CardHeader className="pb-3">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <Wallet className="w-4 h-4 text-primary" />
            <CardTitle className="text-xs font-black uppercase tracking-wider">
              Resource Allocation
            </CardTitle>
          </div>
          <div className="flex items-center gap-2">
            {isOverallocated && (
              <div className={cn(
                "flex items-center gap-1 px-2 py-1 rounded-full text-[10px] font-bold",
                isCritical ? "bg-red-500/20 text-red-400" : "bg-amber-500/20 text-amber-400"
              )}>
                <AlertTriangle className="w-3 h-3" />
                {isCritical ? 'Critical' : 'Warning'}
              </div>
            )}
            <span className="text-xs font-mono font-bold text-muted-foreground">
              {formatMoney(totalWeeklyBurn)}/wk
            </span>
          </div>
        </div>
      </CardHeader>

      <CardContent className="space-y-4">
        {/* Runway indicator */}
        <div className="flex items-center justify-between p-3 rounded-lg bg-muted/30">
          <span className="text-[10px] font-bold uppercase tracking-wider text-muted-foreground">
            Cash Runway
          </span>
          <div className="flex items-center gap-2">
            <div className={cn(
              "text-sm font-black font-display",
              isCritical ? "text-red-400" : isOverallocated ? "text-amber-400" : "text-emerald-400"
            )}>
              {Math.floor(runway)} weeks
            </div>
            <div className={cn(
              "w-2 h-2 rounded-full",
              isCritical ? "bg-red-500 animate-pulse" : isOverallocated ? "bg-amber-500" : "bg-emerald-500"
            )} />
          </div>
        </div>

        {/* Project burn chart */}
        {allocationData.length > 0 ? (
          <div className="h-32">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={allocationData} layout="vertical" margin={{ top: 0, right: 0, left: 0, bottom: 0 }}>
                <XAxis type="number" hide />
                <YAxis 
                  dataKey="name" 
                  type="category" 
                  width={80}
                  tick={{ fontSize: 9, fontWeight: 700 }}
                  axisLine={false}
                  tickLine={false}
                />
                <Tooltip
                  content={({ active, payload }) => {
                    if (active && payload && payload.length) {
                      const data = payload[0].payload;
                      return (
                        <div className="bg-card border border-border p-2 rounded-lg shadow-lg">
                          <p className="text-xs font-bold mb-1">{data.fullName}</p>
                          <p className="text-[10px] text-muted-foreground">{data.state}</p>
                          <div className="mt-2 space-y-1">
                            <div className="flex justify-between text-[10px]">
                              <span>Weekly Cost:</span>
                              <span className="font-mono font-bold">{formatMoney(data.weeklyCost)}</span>
                            </div>
                            <div className="flex justify-between text-[10px]">
                              <span>Budget Used:</span>
                              <span className={cn(
                                "font-mono font-bold",
                                data.percentUsed > 90 ? "text-red-400" : data.percentUsed > 70 ? "text-amber-400" : "text-emerald-400"
                              )}>
                                {Math.round(data.percentUsed)}%
                              </span>
                            </div>
                          </div>
                        </div>
                      );
                    }
                    return null;
                  }}
                />
                <Bar dataKey="weeklyCost" radius={[0, 4, 4, 0]} maxBarSize={20}>
                  {allocationData.map((entry, index) => (
                    <Cell 
                      key={`cell-${index}`} 
                      fill={entry.percentUsed > 90 ? '#ef4444' : entry.percentUsed > 70 ? '#f59e0b' : '#22c55e'}
                    />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        ) : (
          <div className="h-32 flex items-center justify-center text-muted-foreground">
            <p className="text-sm">No active production costs</p>
          </div>
        )}

        {/* State breakdown */}
        <div className="grid grid-cols-3 gap-2">
          {Object.entries(stateGroups).map(([state, projects]) => {
            const total = projects.reduce((sum, p) => sum + p.weeklyCost, 0);
            if (total === 0) return null;

            return (
              <div key={state} className="p-2 rounded-lg bg-background/50 text-center">
                <p className="text-[9px] font-bold uppercase text-muted-foreground mb-1">{state}</p>
                <p className="text-xs font-mono font-bold">{formatMoney(total)}</p>
                <p className="text-[9px] text-muted-foreground">{projects.length} projects</p>
              </div>
            );
          })}
        </div>
      </CardContent>
    </Card>
  );
};

