import React, { useEffect, useState } from 'react';
import { Button } from '@/components/ui/button';
import { Download, RefreshCw, X } from 'lucide-react';
import { cn } from '@/lib/utils';

/**
 * Handles two banners:
 * 1. "Install" — shown when the browser fires beforeinstallprompt (Chrome/Edge on Mac)
 * 2. "Update ready" — shown when a new service worker is waiting
 * 
 * NOTE: PWA functionality is disabled for Electron desktop app
 */

interface BeforeInstallPromptEvent extends Event {
  prompt: () => Promise<void>;
  userChoice: Promise<{ outcome: 'accepted' | 'dismissed' }>;
}

// Check if running in Electron environment
const isElectron = typeof window !== 'undefined' && 'electronAPI' in window;

// Stub PWA functionality since PWA plugin is removed for Electron
const needRefresh = false;
const updateServiceWorker = () => {};

// Try to load PWA module if available (for web version)
try {
  // @ts-expect-error - Virtual module provided by vite-plugin-pwa (may not exist)
  require('virtual:pwa-register/react');
} catch {
  // PWA module not available (Electron or plugin removed)
  console.log('PWA module not available (expected for Electron)');
}

export function InstallPrompt() {
  const [installEvent, setInstallEvent] = useState<BeforeInstallPromptEvent | null>(null);
  const [dismissed, setDismissed] = useState(false);

  // Load dismissed state from electron-store or localStorage
  useEffect(() => {
    const loadDismissedState = async () => {
      if (isElectron && window.electronAPI) {
        try {
          const dismissed = await window.electronAPI.store.get('pwa-install-dismissed');
          setDismissed(dismissed === '1');
        } catch (e) {
          console.error('Failed to load dismissed state from electron-store:', e);
        }
      } else {
        try {
          setDismissed(localStorage.getItem('pwa-install-dismissed') === '1');
        } catch (e) {
          console.error('Failed to load dismissed state from localStorage:', e);
        }
      }
    };
    loadDismissedState();
  }, []);

  useEffect(() => {
    // Only add beforeinstallprompt listener in web mode
    if (!isElectron) {
      const handler = (e: Event) => {
        e.preventDefault();
        setInstallEvent(e as BeforeInstallPromptEvent);
      };
      window.addEventListener('beforeinstallprompt', handler);
      return () => window.removeEventListener('beforeinstallprompt', handler);
    }
  }, []);

  const handleInstall = async () => {
    if (!installEvent) return;
    await installEvent.prompt();
    const { outcome } = await installEvent.userChoice;
    if (outcome === 'accepted') setInstallEvent(null);
  };

  const handleDismiss = async () => {
    setDismissed(true);
    if (isElectron && window.electronAPI) {
      try {
        await window.electronAPI.store.set('pwa-install-dismissed', '1');
      } catch (e) {
        console.error('Failed to save dismissed state to electron-store:', e);
      }
    } else {
      try {
        localStorage.setItem('pwa-install-dismissed', '1');
      } catch (e) {
        console.error('Failed to save dismissed state to localStorage:', e);
      }
    }
    setInstallEvent(null);
  };

  // PWA features are disabled in Electron
  if (isElectron) {
    return null;
  }

  // Update banner (only in web mode with PWA)
  if (needRefresh && !isElectron) {
    return (
      <div className={cn(
        'fixed bottom-6 left-1/2 -translate-x-1/2 z-[9999]',
        'flex items-center gap-3 px-5 py-3 rounded-xl',
        'bg-indigo-950/95 border border-indigo-500/40 backdrop-blur-md shadow-2xl',
        'text-white'
      )}>
        <RefreshCw className="w-5 h-5 text-indigo-400" />
        <span className="text-sm font-medium">Update available</span>
        <Button
          size="sm"
          variant="outline"
          className="bg-white/10 border-white/20 hover:bg-white/20 text-white"
          onClick={() => updateServiceWorker()}
        >
          Update
        </Button>
        <button
          onClick={handleDismiss}
          className="p-1 hover:bg-white/10 rounded-lg transition-colors"
        >
          <X className="w-4 h-4" />
        </button>
      </div>
    );
  }

  // Install banner (only in browsers, not Electron)
  if (!isElectron && installEvent && !dismissed) {
    return (
      <div className={cn(
        'fixed bottom-6 left-1/2 -translate-x-1/2 z-[9999]',
        'flex items-center gap-3 px-5 py-3 rounded-xl',
        'bg-indigo-950/95 border border-indigo-500/40 backdrop-blur-md shadow-2xl',
        'text-white'
      )}>
        <Download className="w-5 h-5 text-indigo-400" />
        <span className="text-sm font-medium">Install Studio Boss</span>
        <Button
          size="sm"
          variant="outline"
          className="bg-white/10 border-white/20 hover:bg-white/20 text-white"
          onClick={handleInstall}
        >
          Install
        </Button>
        <button
          onClick={handleDismiss}
          className="p-1 hover:bg-white/10 rounded-lg transition-colors"
        >
          <X className="w-4 h-4" />
        </button>
      </div>
    );
  }

  return null;
}

import React from 'react';
import { TimeSeriesChart } from '@/components/charts/TimeSeriesChart';
import { Card } from '@/components/ui/card';
import { tokens } from '@/lib/tokens';
import { cn } from '@/lib/utils';
import { TrendingUp, TrendingDown, Flame, Snowflake } from 'lucide-react';
import { Badge } from '@/components/ui/badge';
import { useGameStore } from '@/store/gameStore';
import { selectMarketTrends } from '@/store/selectors';

interface GenreTrendPoint {
  week: number;
  heat: number; // 0-100
}

interface GenreTrendLineProps {
  genre?: string;
  data?: GenreTrendPoint[];
  trend?: 'rising' | 'stable' | 'cooling';
  className?: string;
}

export const GenreTrendLine: React.FC<GenreTrendLineProps> = ({
  genre: externalGenre,
  data: externalData,
  trend: externalTrend,
  className,
}) => {
  const gameState = useGameStore(s => s.gameState);
  const allTrends = selectMarketTrends(gameState);

  // Filter by genre if specified
  const genreTrends = externalGenre 
    ? allTrends.filter(t => t.genre === externalGenre)
    : allTrends;

  const data = externalData || genreTrends.map(t => ({
    week: t.week,
    heat: t.heat || 50
  }));

  const genre = externalGenre || genreTrends[0]?.genre || 'Action';

  // Determine trend from data
  const trend = externalTrend || (() => {
    if (data.length < 2) return 'stable';
    const recent = data.slice(-4);
    const avgChange = recent.reduce((sum, d, i) => {
      if (i === 0) return 0;
      return sum + (d.heat - recent[i-1].heat);
    }, 0) / Math.max(recent.length - 1, 1);
    if (avgChange > 2) return 'rising';
    if (avgChange < -2) return 'cooling';
    return 'stable';
  })();
  const currentHeat = data[data.length - 1]?.heat || 0;
  const previousHeat = data[data.length - 2]?.heat || currentHeat;
  const change = currentHeat - previousHeat;

  const chartData = data.map(d => ({
    date: `W${d.week}`,
    value: d.heat,
  }));

  const getTrendIcon = () => {
    switch (trend) {
      case 'rising': return <TrendingUp className="h-4 w-4 text-red-500" />;
      case 'cooling': return <TrendingDown className="h-4 w-4 text-blue-500" />;
      default: return <Snowflake className="h-4 w-4 text-slate-400" />;
    }
  };

  const getTrendBadge = () => {
    switch (trend) {
      case 'rising':
        return (
          <Badge className="text-[9px] bg-red-500/20 text-red-500">
            <Flame className="h-3 w-3 mr-1" />
            Hot
          </Badge>
        );
      case 'cooling':
        return (
          <Badge className="text-[9px] bg-blue-500/20 text-blue-500">
            <Snowflake className="h-3 w-3 mr-1" />
            Cooling
          </Badge>
        );
      default:
        return <Badge variant="outline" className="text-[9px]">Stable</Badge>;
    }
  };

  const getHeatColor = (heat: number) => {
    if (heat >= 80) return '#ef4444';
    if (heat >= 60) return '#f59e0b';
    if (heat >= 40) return '#3b82f6';
    return '#94a3b8';
  };

  return (
    <Card className={cn('p-3', tokens.border.default, className)}>
      <div className="flex items-center justify-between mb-2">
        <div className="flex items-center gap-2">
          <span className="font-bold text-sm">{genre}</span>
          {getTrendBadge()}
        </div>
        <div className="flex items-center gap-1">
          <span 
            className="text-lg font-bold"
            style={{ color: getHeatColor(currentHeat) }}
          >
            {currentHeat}
          </span>
          <span className="text-[10px] text-muted-foreground">/100</span>
        </div>
      </div>

      <TimeSeriesChart
        data={chartData}
        height={80}
        lineColor={getHeatColor(currentHeat)}
        showArea={true}
        showGrid={false}
        valueFormatter={(v) => `${v}`}
      />

      <div className="flex items-center justify-between mt-2 text-[10px]">
        <span className={cn(
          'font-medium',
          change > 0 ? 'text-red-500' : change < 0 ? 'text-blue-500' : 'text-slate-400'
        )}>
          {change > 0 ? '+' : ''}{change} this week
        </span>
        {getTrendIcon()}
      </div>
    </Card>
  );
};

export default GenreTrendLine;

