        />
      )}
    </div>
  );
};

import React, { useMemo, useState } from 'react';
import { useGameStore } from '@/store/gameStore';
import { Buyer, Project, ProjectContractType } from '@/engine/types';
import { RandomGenerator } from '@/engine/utils/rng';
import { Dialog, DialogContent } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { 
  Handshake, 
  Film, 
  CheckCircle2, 
  XCircle
} from 'lucide-react';
import { cn } from '@/lib/utils';
import { calculateFitScore } from '@/engine/systems/buyers';
import { TooltipWrapper } from '@/components/ui/tooltip-wrapper';

const DEAL_TYPE_TOOLTIPS = {
  standard: "Balanced revenue share and license fee. The industry standard baseline.",
  deficit: "Higher back-end revenue share in exchange for a lower upfront license fee. High risk, high reward.",
  upfront: "Higher upfront payment to cover production costs at the expense of back-end participation."
};

interface DealModalProps {
  buyer: Buyer;
  open: boolean;
  onClose: () => void;
}

export const DealModal: React.FC<DealModalProps> = ({ buyer, open, onClose }) => {
  const { gameState, pitchProject } = useGameStore();
  const [selectedProject, setSelectedProject] = useState<string | null>(null);
  const [contractType, setContractType] = useState<ProjectContractType>('standard');
  const [isPitching, setIsPitching] = useState(false);
  const [dealResult, setDealResult] = useState<{ success: boolean; message: string } | null>(null);

  const eligibleProjects = useMemo(() => {
    if (!gameState) return [];
    return Object.values(gameState?.entities.projects || {}).filter(
      (p: Project) => p.state === 'development' || p.state === 'production' || p.state === 'needs_greenlight'
    );
  }, [gameState]);

  const selectedProjectObj = useMemo(
    () => eligibleProjects.find(p => p.id === selectedProject),
    [eligibleProjects, selectedProject]
  );

  const fitScore = useMemo(() => {
    if (!selectedProjectObj || !gameState) return 0;
    const rng = new RandomGenerator(gameState.gameSeed + gameState.week);
    return calculateFitScore(selectedProjectObj, buyer, gameState.week, gameState.entities.projects, rng);
  }, [selectedProjectObj, buyer, gameState]);

  const handlePitch = async () => {
    if (!selectedProject) return;
    setIsPitching(true);

    // Artificial delay for "Negotiation" feel
    await new Promise(resolve => setTimeout(resolve, 800));

    const success = await pitchProject(selectedProject, buyer.id, contractType);

    setDealResult({
      success,
      message: success 
        ? `${buyer.name} has greenlit "${selectedProjectObj?.title}" on a ${contractType} deal!` 
        : `${buyer.name} passed on the pitch. The project's current fit score (${Math.round(fitScore)}) didn't meet their executive mandate.`
    });
    setIsPitching(false);
  };

  return (
    <Dialog open={open} onOpenChange={onClose}>
      <DialogContent className="max-w-xl bg-card border-border shadow-2xl overflow-hidden p-0 text-left">
        <div className="absolute top-0 inset-x-0 h-1 bg-gradient-to-r from-primary via-violet-500 to-primary/20" />

        <div className="p-6 space-y-6">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 rounded-xl bg-primary/10 border border-primary/20 flex items-center justify-center shadow-inner text-left">
               <Handshake className="w-6 h-6 text-primary" />
            </div>
            <div>
              <h3 className="text-xl font-black uppercase tracking-tighter italic">Studio Distribution Negotiation</h3>
              <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">{buyer.name} • Executive Review</p>
            </div>
          </div>

          {dealResult ? (
            <div className={cn(
               "p-6 rounded-2xl border animate-in zoom-in-95 duration-300",
               dealResult.success ? "bg-emerald-500/10 border-emerald-500/20" : "bg-rose-500/10 border-rose-500/20"
            )}>
              <div className="flex items-start gap-4">
                {dealResult.success ? (
                  <CheckCircle2 className="w-8 h-8 text-emerald-500" />
                ) : (
                  <XCircle className="w-8 h-8 text-rose-500" />
                )}
                <div className="space-y-2">
                   <h4 className={cn("text-sm font-black uppercase tracking-widest", dealResult.success ? "text-emerald-500" : "text-rose-500")}>
                     {dealResult.success ? 'Deal Signed!' : 'Pitch Rejected'}
                   </h4>
                   <p className="text-sm text-muted-foreground leading-relaxed italic">"{dealResult.message}"</p>
                   <Button onClick={onClose} className="mt-4 h-9 text-[10px] font-black uppercase" variant="outline">Back to Dashboard</Button>
                </div>
              </div>
            </div>
          ) : (
            <>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {/* Project Selection */}
                <div className="space-y-3">
                   <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-muted-foreground flex items-center gap-2">
                     <Film className="w-4 h-4" /> Available Slate
                   </h4>
                   <div className="space-y-2 max-h-[240px] overflow-y-auto pr-1">
                      {eligibleProjects.map(p => (
                        <button aria-pressed={selectedProject === p.id}
                          key={p.id}
                          onClick={() => setSelectedProject(p.id)}
                          className={cn(
                            "w-full text-left p-3 rounded-xl border transition-all relative overflow-hidden group",
                            selectedProject === p.id ? "bg-primary/10 border-primary/40" : "bg-white/5 border-white/5 hover:border-white/10"
                          )}
                        >
                          {selectedProject === p.id && <div className="absolute left-0 top-0 bottom-0 w-1 bg-primary" />}
                          <div className="font-black text-xs uppercase truncate group-hover:text-primary transition-colors">{p.title}</div>
                          <div className="text-[9px] font-bold text-muted-foreground/60 uppercase tracking-widest mt-0.5">{p.genre} • {p.budgetTier}</div>
                        </button>
                      ))}
                   </div>
                </div>

                {/* Analysis Column */}
                <div className="space-y-4 text-left">
                   <div className="glass-panel p-5 rounded-2xl border border-white/5 bg-black/20 space-y-4">
                      <div className="flex items-center justify-between">
                         <TooltipWrapper tooltip="Algorithmic alignment score between your project's genre/talent and the platform's current executive mandate." side="top">
                           <span className="text-[10px] font-black uppercase tracking-widest text-muted-foreground cursor-help">Strategic Fit</span>
                         </TooltipWrapper>
                         <span className={cn("text-lg font-black italic", fitScore >= 70 ? 'text-emerald-400' : fitScore >= 50 ? 'text-primary' : 'text-rose-400')}>
                           {Math.round(fitScore)}%
                         </span>
                      </div>
                      <div className="h-1.5 rounded-full bg-white/5 overflow-hidden">
                        <div 
                          className={cn("h-full transition-all duration-700", fitScore >= 70 ? 'bg-emerald-500' : fitScore >= 50 ? 'bg-primary' : 'bg-rose-500')} 
                          style={{ width: `${fitScore}%` }}
                        />
                      </div>
                      <p className="text-[10px] font-bold text-muted-foreground italic leading-snug">
                        {selectedProjectObj 
                          ? (fitScore >= 50 ? `${buyer.name} is showing positive early interest in this genre.` : `${buyer.name} is hesitant about this package's commercial floor.`)
                          : 'Select a project to analyze mandate alignment.'}
                      </p>
                   </div>

                   <div className="space-y-2">
                      <span className="text-[10px] font-black uppercase tracking-widest text-muted-foreground">Deal Structure</span>
                      <div className="flex gap-2">
                        {(['standard', 'deficit', 'upfront'] as ProjectContractType[]).map(t => (
                          <TooltipWrapper key={t} tooltip={DEAL_TYPE_TOOLTIPS[t]} side="bottom">
                            <button aria-pressed={contractType === t}
                              onClick={() => setContractType(t)}
                              className={cn(
                                "flex-1 h-11 p-2 rounded-lg border text-[9px] font-black uppercase tracking-widest transition-all",
                                contractType === t ? "bg-primary text-black border-primary shadow-lg" : "bg-white/5 border-white/5 text-muted-foreground hover:bg-white/10"
                              )}
                            >
                              {t}
                            </button>
                          </TooltipWrapper>
                        ))}
                      </div>
                   </div>
                </div>
              </div>

              <div className="pt-4 border-t border-white/5 flex gap-3">
                 <Button variant="ghost" onClick={onClose} className="h-12 px-6 text-[10px] font-black uppercase">Cancel</Button>
                 <Button 
                   onClick={handlePitch}
                   disabled={!selectedProject || isPitching}
                   tooltip="Officially present the content package to the executive board for greenlight review"
                   className="flex-1 h-12 bg-primary text-black hover:bg-primary/90 font-black text-xs uppercase tracking-[0.2em] shadow-xl shadow-primary/10 relative overflow-hidden"
                 >
                   {isPitching ? <div className="flex items-center gap-2"><div className="w-3 h-3 border-2 border-black/30 border-t-black rounded-full animate-spin" /> Reviewing Package...</div> : 'Send Official Pitch'}
                 </Button>
              </div>
            </>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
};

import React from 'react';
import { Buyer, StreamerPlatform, NetworkPlatform } from '@/engine/types';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { 
  Wifi, 
  Radio, 
  Crown, 
  Users, 
  AlertTriangle, 
  Handshake, 
  TrendingUp, 
  TrendingDown,
  Globe,
  Star
} from 'lucide-react';
import { cn } from '@/lib/utils';
import { SubscriberTrendChart } from './SubscriberTrendChart';
import { TooltipWrapper } from '@/components/ui/tooltip-wrapper';

const ARCHETYPE_CONFIG = {
  streamer: { icon: Wifi, label: 'Streamer', color: 'text-violet-400', bg: 'bg-violet-500/10', border: 'border-violet-500/20', tooltip: 'Global digital distribution platform focusing on subscriber growth and library depth.' },
  network: { icon: Radio, label: 'Network', color: 'text-blue-400', bg: 'bg-blue-500/10', border: 'border-blue-500/20', tooltip: 'Traditional broadcast or cable network focusing on domestic reach and advertising.' },
  premium: { icon: Crown, label: 'Premium', color: 'text-amber-400', bg: 'bg-amber-500/10', border: 'border-amber-500/20', tooltip: 'High-end subscription service focusing on prestige content and exclusive talent deals.' },
} as const;

function formatSubscribers(n: number): string {
  if (n >= 1_000_000_000) return `${(n / 1_000_000_000).toFixed(1)}B`;
  if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`;
  if (n >= 1_000) return `${(n / 1_000).toFixed(0)}K`;
  return n.toString();
}

interface PlatformCardProps {
  buyer: Buyer;
  allBuyers: Buyer[];
  onDeal: (buyer: Buyer) => void;
  onViewHistory: (buyer: Buyer) => void;
}

export const PlatformCard: React.FC<PlatformCardProps> = ({ buyer, allBuyers, onDeal, onViewHistory }) => {
  const config = ARCHETYPE_CONFIG[buyer.archetype];
  const Icon = config.icon;
  const isAcquired = !!buyer.acquiredBy;
  const acquirer = isAcquired ? allBuyers.find(b => b.id === buyer.acquiredBy) : null;
  const strength = buyer.strength ?? 60;

  // Trend Calculation
  const isStreamer = buyer.archetype === 'streamer';
  const streamer = buyer as StreamerPlatform;
  const history = streamer.subscriberHistory || [];
  const lastSubCount = history.length > 1 ? history[history.length - 2].count : streamer.subscribers;
  const trend = streamer.subscribers - lastSubCount;
  const isTrendingUp = trend >= 0;

  return (
    <div className={cn(
      "p-5 rounded-2xl border backdrop-blur-md transition-all duration-300 space-y-4 group relative overflow-hidden flex flex-col justify-between",
      isAcquired 
        ? "border-muted/30 bg-muted/5 opacity-60 grayscale-[0.5]" 
        : buyer.isAcquirable 
          ? "border-destructive/30 bg-destructive/5 animate-pulse-slow" 
          : strength > 75 
            ? "border-primary/20 bg-card/80 shadow-[0_0_20px_rgba(var(--primary),0.05)]" 
            : "border-border/30 bg-card/60",
      "hover:shadow-xl hover:-translate-y-1 hover:border-primary/30"
    )}>
      {/* Glossy Overlay */}
      <div className="absolute inset-0 bg-gradient-to-br from-white/5 to-transparent pointer-events-none" />

      {/* Header */}
      <div className="flex items-start justify-between gap-3 relative z-10">
        <div className="flex items-center gap-3">
          <TooltipWrapper tooltip={config.tooltip} side="top">
            <div className={cn("w-10 h-10 rounded-xl flex items-center justify-center border shadow-inner cursor-help", config.bg, config.border)}>
              <Icon className={cn("w-5 h-5", config.color)} />
            </div>
          </TooltipWrapper>
          <div>
            <h3>
              <button
                type="button"
                className="font-display font-black text-[15px] tracking-tight text-foreground leading-tight group-hover:text-primary transition-colors cursor-pointer text-left"
                onClick={() => onViewHistory(buyer)}
              >
                {buyer.name}
              </button>
            </h3>
            <div className="flex items-center gap-1.5 mt-1">
              <Badge variant="outline" className={cn("text-[9px] font-black tracking-widest uppercase px-1.5 py-0 h-4 border-none", config.bg, config.color)}>
                {config.label}
              </Badge>
              {isAcquired && (
                <Badge variant="outline" className="text-[8px] font-black tracking-widest uppercase px-1.5 py-0 h-4 bg-white/5 border-white/5 text-muted-foreground/60 leading-none">
                  <Globe className="w-2.5 h-2.5 mr-0.5" /> Subsidiary
                </Badge>
              )}
            </div>
          </div>
        </div>

        {buyer.currentMandate && (
          <TooltipWrapper tooltip="The primary strategic goal for this platform. Alignment increases the probability of deal acceptance and higher valuations." side="left">
            <div className="flex flex-col items-end cursor-help">
              <span className="text-[7px] font-black text-muted-foreground/40 uppercase tracking-[0.2em] mb-1">Active Mandate</span>
              <Badge variant="secondary" className="text-[9px] font-bold uppercase tracking-widest bg-emerald-500/10 text-emerald-400 border border-emerald-500/20 px-2">
                {buyer.currentMandate.type.replace('_', ' ')}
              </Badge>
            </div>
          </TooltipWrapper>
        )}
      </div>

      {/* Chart Section (Streamer Only) */}
      {isStreamer && (
        <TooltipWrapper tooltip="Subscriber trajectory over the last 12 weeks. Trends influence platform valuation and buying power." side="top">
          <div className="h-20 w-full relative z-10 my-1 overflow-hidden rounded-lg bg-black/20 border border-white/5 p-1 group/chart cursor-help">
             <SubscriberTrendChart platform={streamer} />
             <div className="absolute top-1 right-2 flex items-center gap-1 text-[8px] font-black uppercase tracking-widest">
                {isTrendingUp ? (
                  <TrendingUp className="w-2.5 h-2.5 text-emerald-400" />
                ) : (
                  <TrendingDown className="w-2.5 h-2.5 text-rose-400" />
                )}
                <span className={isTrendingUp ? 'text-emerald-400' : 'text-rose-400'}>
                  {Math.abs(trend) > 0 ? formatSubscribers(Math.abs(trend)) : 'Steady'}
                </span>
             </div>
          </div>
        </TooltipWrapper>
      )}

      {/* Stats Grid */}
      <div className={cn(
        "grid gap-3 text-xs pt-3 border-t border-white/5 relative z-10",
        buyer.archetype === 'streamer' ? 'grid-cols-2' : 'grid-cols-2'
      )}>
        {buyer.archetype === 'streamer' && (
          <TooltipWrapper tooltip="Total number of paying users on this digital network." side="bottom">
            <div className="space-y-1 cursor-help">
              <div className="text-[9px] uppercase font-black tracking-widest text-muted-foreground/40 leading-none">Global Subs</div>
              <div className="font-black text-foreground flex items-center gap-1.5 text-sm">
                <Users className="w-3.5 h-3.5 text-violet-400" />
                {formatSubscribers((buyer as StreamerPlatform).subscribers)}
              </div>
            </div>
          </TooltipWrapper>
        )}
        {buyer.archetype === 'network' && (
          <TooltipWrapper tooltip="Estimated percentage of households reached by this broadcast network." side="bottom">
            <div className="space-y-1 cursor-help">
              <div className="text-[9px] uppercase font-black tracking-widest text-muted-foreground/40 leading-none">Domestic Reach</div>
              <div className="font-black text-foreground text-sm flex items-center gap-1.5">
                <Radio className="w-3.5 h-3.5 text-blue-400" />
                {(buyer as NetworkPlatform).reach}/100
              </div>
            </div>
          </TooltipWrapper>
        )}
        <TooltipWrapper tooltip="Market capitalization and competitive influence index. Higher strength equals better deal terms." side="bottom">
          <div className="space-y-1 cursor-help">
            <div className="text-[9px] uppercase font-black tracking-widest text-muted-foreground/40 leading-none">Market Strength</div>
            <div className={cn("font-black text-sm flex items-center gap-1.5", strength > 70 ? 'text-emerald-400' : strength > 40 ? 'text-foreground' : 'text-rose-400')}>
              <TrendingUp className="w-3.5 h-3.5" />
              {strength.toFixed(0)}
            </div>
          </div>
        </TooltipWrapper>
      </div>

      {/* Actions */}
      <div className="pt-3 border-t border-white/5 flex gap-2 relative z-10">
        {!isAcquired ? (
           <Button
              variant="outline"
              size="sm"
              tooltip={`Initiate license negotiations with ${buyer.name}`}
              className="flex-1 h-8 text-[9px] uppercase font-black tracking-[0.2em] bg-white/5 border-white/5 hover:bg-primary hover:text-black hover:border-primary transition-all group scale-100 active:scale-95"
              onClick={() => onDeal(buyer)}
            >
              <Handshake className="w-3.5 h-3.5 mr-2 group-hover:rotate-12 transition-transform" />
              Pitch Deal
            </Button>
        ) : (
          <div className="flex-1 h-8 flex items-center justify-center text-[9px] uppercase font-black tracking-[0.2em] text-muted-foreground/40 bg-white/2 bg-dotted border border-white/5 rounded-md">
            Controlled by {acquirer?.name}
          </div>
        )}

        <Button
          variant="outline"
          size="sm"
          tooltip={`View ${buyer.name} industry intelligence and M&A history`}
          className="w-8 h-8 p-0 bg-white/5 border-white/5 hover:border-primary/40 hover:text-primary transition-all"
          onClick={() => onViewHistory(buyer)}
        >
          <Star className="w-3.5 h-3.5" />
        </Button>
      </div>

      {/* Vulnerability Alert */}
      {buyer.isAcquirable && !isAcquired && (
        <TooltipWrapper tooltip="This platform is currently vulnerable to a corporate takeover." side="top">
          <div className="absolute top-2 right-2 flex items-center gap-1.5 bg-rose-500/10 border border-rose-500/20 px-2 py-0.5 rounded-full animate-pulse cursor-help">
             <AlertTriangle className="w-2.5 h-2.5 text-rose-500" />
             <span className="text-[8px] font-black text-rose-500 uppercase tracking-widest">M&A Target</span>
          </div>
        </TooltipWrapper>
      )}
    </div>
  );
};

import React, { useMemo, useState } from 'react';
import { useGameStore } from '@/store/gameStore';
import { Project, TalentRole } from '@/engine/types';
import { formatMoney } from '@/engine/utils';
import { getRecommendedTalentForProject } from '@/engine/utils/projectUtils';
import { selectTalentPool } from '@/store/selectors';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { 
  Users, 
  Search, 
  Star, 
  TrendingUp, 
  X,
  Target
} from 'lucide-react';
import { cn } from '@/lib/utils';
import { TalentAvatar } from './TalentAvatar';
import { CastingFeedback } from './CastingFeedback';
import { useUIStore } from '@/store/uiStore';

interface TalentAttachmentPanelProps {
  project: Project;
  onClose?: () => void;
}

export const TalentAttachmentPanel: React.FC<TalentAttachmentPanelProps> = ({ project, onClose }) => {
  const gameState = useGameStore(s => s.gameState);
  const signContract = useGameStore(s => s.signContract);
  const { selectTalent } = useUIStore();

  // Filters
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedTier, setSelectedTier] = useState<string>('ALL');
  const [selectedRole, setSelectedRole] = useState<TalentRole | 'ALL'>('ALL');
  const [showMatchesOnly, setShowMatchesOnly] = useState(false);
  const [hoveredTalentId, setHoveredTalentId] = useState<string | null>(null);

  const talentPool = useMemo(() => selectTalentPool(gameState), [gameState]);
  const contracts = useMemo(() => Object.values(gameState?.entities.contracts || {}), [gameState?.entities.contracts]);

  const attachedTalentIds = useMemo(() => {
    return new Set(contracts.filter(c => c.projectId === project.id).map(c => c.talentId));
  }, [contracts, project.id]);

  const attachedTalent = useMemo(() => {
    return talentPool.filter(t => attachedTalentIds.has(t.id));
  }, [talentPool, attachedTalentIds]);

  const filteredTalent = useMemo(() => {
    const pool = talentPool.filter(t => !attachedTalentIds.has(t.id));
    const recommendations = getRecommendedTalentForProject(
      pool,
      project,
      selectedRole === 'ALL' ? undefined : selectedRole,
      Array.from(attachedTalentIds)
    );

    return recommendations.filter(rec => {
      const t = rec.talent;
      const matchesSearch = t.name.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesTier = selectedTier === 'ALL' || t.tier.toString() === selectedTier;
      const matchesRole = selectedRole === 'ALL' || t.roles.includes(selectedRole as TalentRole) || t.role === selectedRole;
      const matchesScore = !showMatchesOnly || rec.score >= 70;

      return matchesSearch && matchesTier && matchesRole && matchesScore;
    });
  }, [talentPool, attachedTalentIds, project, searchQuery, selectedTier, selectedRole, showMatchesOnly]);

  const talentMap = useMemo(() => new Map(talentPool.map(t => [t.id, t])), [talentPool]);
  const hoveredTalent = hoveredTalentId ? talentMap.get(hoveredTalentId) : null;

  return (
    <div className="flex flex-col h-full bg-slate-950/50 rounded-2xl border border-slate-800 overflow-hidden text-left">
      {/* Header / Active Casting */}
      <div className="p-4 border-b border-slate-800 bg-black/40 space-y-4">
        <div className="flex items-center justify-between">
          <h3 className="text-sm font-black uppercase tracking-widest text-white flex items-center gap-2">
            <Target className="w-4 h-4 text-primary" /> Active Production Slate
          </h3>
          {onClose && (
            <Button variant="ghost" size="icon" aria-label="Close panel" onClick={onClose} className="h-8 w-8 text-slate-500 hover:text-white">
              <X className="w-4 h-4" />
            </Button>
          )}
        </div>

        {attachedTalent.length > 0 && (
          <div className="flex flex-wrap gap-2">
            {attachedTalent.map(t => (
              <Badge 
              key={t.id} 
              variant="secondary" 
              className="bg-emerald-500/10 text-emerald-400 border-emerald-500/20 py-1 pl-1 pr-2 gap-2 flex items-center h-8 cursor-pointer hover:border-emerald-500/50 transition-colors"
              aria-label={`View ${t.name} profile`} onClick={() => selectTalent(t.id)}
            >
                <TalentAvatar talent={t} size="xs" />
                <span className="text-[10px] font-black">{t.name}</span>
              </Badge>
            ))}
          </div>
        )}
      </div>

